window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["techniques"]={"updatedAt":"2026-06-16","count":119,"techniques":[{"id":"tu-thuat-na-di","name":"Tử thuật - Na di","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tử hệ (Thiên Vận Tông)","soHuu":["Tứ sư tỷ (Tử hệ)"],"blurb":"Pháp thuật của Tử hệ Thiên Vận Tông; bắt quyết điểm vào hư không, một tia sáng bạc lan ra bao trùm phạm vi mười dặm trong nháy mắt.","detail":"Tử thuật - Na di là pháp thuật của tứ sư tỷ thuộc Tử hệ Thiên Vận Tông. Người thi triển bắt quyết điểm tay vào hư không, một tia sáng bạc từ cơ thể điên cuồng lan ra, trong nháy mắt bao trùm phạm vi mười dặm. Trong chương, thuật này được dùng để mở màn cuộc vây kích Vương Lâm tại Tử Lâm Các.","nguon":["@c0458"]},{"id":"tran-phap-khoa-pham-linh-cac","name":"Trận pháp khóa Phẩm Linh Các","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Thiên Vận Tông","soHuu":[],"blurb":"Trận pháp khóa Phẩm Linh Các với ba đạo bạch ngân giao nhau; ấn lệnh bài vào chỗ giao sẽ kích hoạt cửa truyền tống lên tầng thứ bảy.","detail":"Trận pháp bảo vệ Phẩm Linh Các có ba đạo bạch ngân giao nhau dưới mặt đất. Khi ấn lệnh bài vào chỗ giao, ba đạo bạch ngân điên cuồng lao ra xuyên qua lệnh bài, hợp thành một khối khiến lệnh bài phát ánh sáng tím khuếch tán, rồi nối thành một cánh cửa lớn truyền tống tại tầng thứ bảy.","nguon":["@c0458"]},{"id":"than-thong-na-di-tu-su-ty","name":"Thần thông na di (tứ sư tỷ)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tử hệ (Thiên Vận Tông)","soHuu":["Tứ sư tỷ (Tử hệ)"],"blurb":"Thần thông dịch chuyển không gian của tứ sư tỷ, dời người tới nơi khác trong nháy mắt.","detail":"Thần thông na di cho phép khóa chặt không gian bốn phía ngăn đối phương na di, đồng thời dịch chuyển người tới địa điểm xa trong chớp mắt. Tứ sư tỷ dùng nó đưa Vương Lâm tới thạch lâm khốn địa ngoài Thiên Vận Tông hơn mười ngàn dặm, và hứa truyền lại cho Vương Lâm sau khi mọi chuyện giải quyết xong.","nguon":["@c0459"]},{"id":"tran-phap-thach-lam-khon-dia","name":"Trận pháp thạch lâm khốn địa","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Thiên Vận Tông","soHuu":["Đại sư huynh (Thiên Vận Tông)"],"blurb":"Trận pháp vây khốn do đại sư huynh bố trí trên thạch lâm, triệt tiêu mọi đòn công kích và ngăn thoát ra.","detail":"Trận pháp được khắc bằng những vết sâu trên các cự thạch trong thạch lâm, tạo màn sáng bạc bao phủ phạm vi mười dặm. Bên trong có lực cản đè từ trên xuống tương đương tu sĩ Anh Biến hậu kỳ toàn lực ra tay; kiếm quang và pháp bảo phóng ra đều ảm đạm rồi tan biến sau vài nhịp thở, người tu cũng không thể bay vượt qua biên giới thạch lâm. Vương Lâm thử phá bằng tiên kiếm, bay thẳng lên và cho Hứa Lập Quốc cùng loan đao lao tới đều thất bại.","nguon":["@c0459"]},{"id":"tu-vu-dai-tran","name":"Tử vụ đại trận","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Đại trận phòng ngự cấp tông","hePhai":"Thiên Vận Tông","soHuu":["Thiên Vận Tông"],"blurb":"Đại trận sương tím khổng lồ bao quanh Thiên Vận Tinh, có thể vận động hoặc tạm ngừng để mở thông đạo.","detail":"Trận sương tím bao trùm Thiên Vận Tinh, vận hành liên tục như hàng rào bảo vệ chủ tinh. Một tháng trước thọ yến, trận tạm ngừng vận động để đệ tử Thiên Vận Tông phái ra nghênh đón khách khắp nơi và mở thông đạo cho tu sĩ năm tiểu tinh cầu cùng lão quái các tiểu tu chân tinh tới chúc thọ.","nguon":["@c0460"]},{"id":"hu-that-nhi-y","name":"Hư Thật nhị ý","loai":"khac","loaiLabel":"Cảnh giới ý cảnh","phamCap":"Cảnh giới truyền thuyết","hePhai":"","soHuu":["Kim Ma tử"],"blurb":"Cảnh giới tu vi trong truyền thuyết, hiếm người chế phục được.","detail":"Cảnh giới ý cảnh truyền thuyết được nhắc đến trong giới tu sĩ vùng Thiên Vận Tinh. Tu vi loại thông thiên hoành hành ngang ngược như Kim Ma tử cũng chỉ có lời đồn đã đạt tới, cho thấy đây là một thang bậc cực cao mà ít ai vươn được.","nguon":["@c0460"]},{"id":"thuong-chi-luc","name":"Thượng chi lực","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tử hệ Thiên Vận Tông","soHuu":["Hứa Lập Quốc"],"blurb":"Thần thông của Hứa Lập Quốc, bấm quyết phóng khí vàng hóa thành đám cát.","detail":"Hứa Lập Quốc (nh�� sư huynh Tử hệ) bấm quyết phóng ra Thượng chi lực: khí vàng hóa thành đám cát lớn như bầy ong, tốc độ nhanh gấp mấy lần người thi triển, dùng để áp sát công kích. Trong trận với Vương Lâm, đám cát này bị Cấm Phiên tạo cơn lốc cấm chế đen xé tan.","nguon":["@c0462"]},{"id":"dai-tu-tai-thien-dia-quyet","name":"Đại tự tại thiên địa quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Tử hệ Thiên Vận Tông","soHuu":["Triệu Tinh Sát"],"blurb":"Công pháp của Triệu Tinh Sát, phát quầng sáng trắng bọc lấy mục tiêu.","detail":"Triệu Tinh Sát thi triển, tay phải liên tục phát ra quầng sáng trắng tản rộng bọc lấy mục tiêu để khống chế. Khi dùng để bọc ma hỏa của Vương Lâm, quầng sáng bị ma hỏa tự bạo thiêu vỡ trong ba nhịp thở.","nguon":["@c0462"]},{"id":"ma-hoa-vuong-lam","name":"Ma hỏa","cn":"","aliases":["Ma diễm"],"loai":"bi-thuat","loaiLabel":"Bí thuật tu ma","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hỏa tu ma của Vương Lâm, đảo ngược tiên lực sinh ma hỏa, có thể tự bạo công kích.","detail":"Vương Lâm đảo ngược tiên lực sinh ma hỏa ở đầu ngón tay. Ma hỏa phóng ra có thể tự bạo, phát tiết ma khí và lửa tím công kích, sức hủy diệt quét ra nghìn trượng tạo hố lớn. Các tu sĩ nhận ra đây là ma diễm của người tu ma cao thâm, từ đó suy đoán thân phận của Vương Lâm.","nguon":["@c0462"]},{"id":"thuat-trieu-co-yeu","name":"Thuật triệu Cổ Yêu","cn":"","loai":"than-thong","loaiLabel":"Yêu thuật triệu hồn","phamCap":"Cấm thuật uy lực vượt cảnh giới","hePhai":"Bí thuật riêng của Triệu Tinh Sát","soHuu":["Triệu Tinh Sát"],"blurb":"Cấm thuật triệu hư ảnh cổ yêu trăm trượng; càng dùng càng tổn hại thân thể người thi triển.","detail":"Người thi triển bấm quyết niệm chú, ký hiệu cổ quái lóe giữa lông mày để gọi ra hư ảnh cổ yêu cao trăm trượng, hai sừng, thân ẩn sắc lam, móng tay như phi kiếm, phát khí yêu tà nồng đậm. Mỗi lần ký hiệu lóe thì hư ảnh càng rõ nhưng thân thể người thi triển càng suy yếu; dùng quá độ sẽ phun máu phản phệ. Triệu Tinh Sát vốn định để dành thuật này cho dịp tranh danh hiệu Thiên Vận Thất Tử nhưng buộc phải dùng trước để đối phó Vương Lâm.","nguon":["@c0463"]},{"id":"yeu-luc","name":"Yêu lực","cn":"","loai":"khac","loaiLabel":"Loại lực lượng","phamCap":"Vượt xa linh lực, ngang tiên lực và ma lực","hePhai":"Lực lượng của cổ yêu","soHuu":[],"blurb":"Khí tức cổ yêu phun ra, vượt xa linh lực và sánh ngang tiên lực, ma lực ma hỏa.","detail":"Khi cổ yêu điểm tay phun ra khí tức, Khương Thiên Tôn nhận ra đó không phải linh lực mà là “Yêu lực” — loại lực lượng vượt xa linh lực, sánh ngang tiên lực và ma lực ma hỏa của Vương Lâm. Yêu lực có thể tạo lốc xoáy đỏ hút linh hồn.","nguon":["@c0463"]},{"id":"cuu-chuyen-luyen-tien-quyet","name":"Cửu Chuyển Luyện Tiên Quyết","cn":"","loai":"bi-thuat","loaiLabel":"Cấm pháp / Tiên thuật phỏng tạo","phamCap":"Phỏng theo hạ phẩm tiên thuật","hePhai":"Tử hệ — Thiên Vận Tông","soHuu":["Vương Lâm","Thiên Vận Tử"],"blurb":"Cấm pháp vận dụng tiên lực theo phương thức quỷ dị, định hình xoắn ốc chín vòng trong cơ thể rồi phóng thích; tích càng lâu uy lực càng lớn.","detail":"Pháp thuật do sư tôn Thiên Vận Tử phỏng theo một hạ phẩm tiên thuật sáng tạo nên dù đạt chín vòng cũng chỉ tương đương uy lực ba vòng của tiên thuật thật. Khi vận chuyển, tiên lực hóa thành kim quang phân cấp nghiêm ngặt — kim tiên lực không cho tiên lực trắng tiếp cận. Vương Lâm đặt tên Cửu Chuyển Luyện Tiên Quyết, tu liên tiếp nhất chuyển (sinh luồng lực sắc bén), nhị chuyển (ba nén hương, sắc bén tăng gấp mười), tam chuyển (gần một canh giờ, đau đớn lục phủ ngũ tạng), cuối cùng ngưng tụ luồng kim tiên lực ở tay trái. Người muốn tu phải có tiên thể loại bỏ phàm cốt sau khi ngưng tiên lực.","nguon":["@c0464"]},{"id":"thuat-dai-na-di","name":"Thuật Đại Na Di","cn":"","aliases":["Cấm pháp dịch chuyển mười vạn dặm"],"loai":"bi-thuat","loaiLabel":"Cấm pháp di chuyển","phamCap":"Cấm pháp","hePhai":"Tử hệ — Thiên Vận Tông","soHuu":["Vương Lâm","Tứ sư tỷ (Tử hệ)"],"blurb":"Cấm pháp dịch chuyển mười vạn dặm, lợi dụng phong ấn bản thân khoảnh khắc trước dịch chuyển để bùng nổ khoảng cách gấp vô số lần.","detail":"Người thi triển lợi dụng khoảnh khắc trước dịch chuyển, dùng cấm pháp phong ấn bản thân để trong nháy mắt liên tục thi triển vài lần pháp thuật dịch chuyển; khi mở phong ấn các lần dịch chuyển đồng loạt bùng nổ, đẩy khoảng cách lên gấp vô số lần. Khi thi triển thân hư ảo, tay phải bấm ấn quyết tạo hào quang bạc, bước bảy bước trong cảm giác đáy biển sâu đông đặc, lực đạo hùng mạnh ngưng tụ rồi thân biến mất xuất hiện cách mười vạn dặm. Rủi ro: nắm không tốt thời gian phong ấn có thể đưa người vào khe không gian; định vị chính xác đòi hỏi thần thức Anh Biến Hậu Kỳ trở lên cộng thông thuộc địa hình. Khoảng cách dịch chuyển ngang ngửa Vấn Đỉnh tu sĩ.","nguon":["@c0464"]},{"id":"yeu-linh-than-thong","name":"Yêu linh (thần thông)","cn":"","aliases":["Yêu linh Triệu Sát Tinh"],"loai":"than-thong","loaiLabel":"Thần thông yêu dị","phamCap":"Tà dị","hePhai":"","soHuu":["Triệu Tinh Sát"],"blurb":"Vật yêu dị được cấy vào cơ thể, giống thần thông Cổ Thần — hại người hại mình, người thi triển chịu lực phản hồi lớn.","detail":"Yêu linh trong cơ thể Triệu Sát Tinh vừa hình thành đã gượng sử dụng, bị Xích Liệt khẳng định cần để sư phụ trừng phạt. Bản chất giống thần thông cổ thần, là vật hại người hại mình — người thi triển chịu lực phản hồi lớn. Đại sư huynh Tử hệ cũng bị sư tôn cấy yêu linh; nếu thức tỉnh sẽ khôi phục bản lãnh.","nguon":["@c0464"]},{"id":"sat-khi-huyet-tinh","name":"Sát Khí Huyết Tinh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cam Tông — Thiên Vận Tông","soHuu":["Người trung niên Cam Tông"],"blurb":"Thần thông/pháp thuật người trung niên Cam Tông dùng năm xưa khi đánh nhau với Sất Hổ ở tiên giới.","detail":"Pháp thuật được người trung niên đệ tử vị trí thứ tư Cam Tông (Thiên Vận Tông) sử dụng năm xưa ở tiên giới khi đối đầu Sất Hổ; thời điểm đó chủ nhân chưa tới Anh Biến, nay đã đạt Anh Biến Hậu Kỳ.","nguon":["@c0464"]},{"id":"thien-van-chi-dao","name":"Thiên Vận Chi Đạo","cn":"","loai":"cong-phap","loaiLabel":"Đạo pháp / Cảm ngộ thiên đạo","phamCap":"Đạo của tiên giả","hePhai":"Thiên Vận Tông","soHuu":["Thiên Vận Tử"],"blurb":"Đạo pháp cốt lõi của Thiên Vận Tử, lấy việc nghe theo mệnh trời làm gốc.","detail":"Thiên Vận Chi Đạo là cảm ngộ thiên đạo của Thiên Vận Tử, cốt lõi là ‘nghe theo mệnh trời’. Trong đại thọ vạn năm, ông đem đạo này ra giảng cho vô số tu sĩ, đồng thời mời người bất đồng quan điểm cứ đề xuất để cùng kiểm chứng. Đây là căn cơ làm nên địa vị thủy tổ của ông ở Thiên Vận Tinh.","nguon":["@c0465"]},{"id":"thien-thuat","name":"Thiên thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử"],"blurb":"Bổn nguyên thần thông theo lý niệm cửu cửu quy nguyên chi vận mà Thiên Vận Tử đã lĩnh hội được chút ít.","detail":"Thiên Vận Tử coi thiên thuật là cửu cửu quy nguyên chi vận, là bổn nguyên thần thông của con đường mình tu, song mới chỉ hiểu được chút ít. Hắn gắn nó với học thuyết ba bước tu đạo: bước thứ ba truy cầu chữ ‘đạo’ chính là thiên vận — thiên vận đến thì tu thành, chưa tới thì hóa đất vàng, ngàn vạn năm thành số không.","nguon":["@c0466"]},{"id":"dan-tien-thuat","name":"Dẫn Tiên thuật","loai":"than-thong","loaiLabel":"Trung phẩm Tiên thuật","phamCap":"Trung phẩm Tiên thuật","hePhai":"","soHuu":["Thiên Vận Tử"],"blurb":"Trung phẩm Tiên thuật Thiên Vận Tử vô ý lấy được từ một tinh cầu bỏ hoang, vốn là thuật người Tiên giới dùng để đưa tu sĩ thăng lên Tiên giới.","detail":"Khi thi triển, người dùng bấm quyết phóng một đạo xích mang lên trời, không trung nổ vang và hiện ra một mảnh màu đỏ với mây cuộn như rồng giận dữ, sấm sét như hàng vạn con rắn bạc lan tỏa. Một cỗ thiên uy vô thanh giáng xuống khiến phần lớn tu sĩ tái mặt, phải hạ xuống khoanh chân ngồi. Tiên thuật vốn cực hiếm, trung phẩm càng hiếm; nghiên cứu cho thấy đây là thuật năm xưa người Tiên giới dùng đưa tu sĩ lên Tiên giới.","nguon":["@c0467"]},{"id":"cam-phap-mo-phong-tien-thuat","name":"Cấm pháp (mô phỏng tiên thuật)","loai":"bi-thuat","loaiLabel":"Pháp thuật","phamCap":"Mô phỏng hạ phẩm tiên thuật","hePhai":"","soHuu":[],"blurb":"Pháp thuật mô phỏng theo hạ phẩm tiên thuật; uy lực đã rất cường đại nhưng vẫn kém xa Tiên thuật thật.","detail":"Trước khi chứng kiến Dẫn Tiên thuật, thứ uy lực cao nhất Vương Lâm từng thấy chỉ là loại Cấm pháp này — được mô phỏng từ hạ phẩm tiên thuật. So với Tiên thuật chân chính, Cấm pháp kém xa cả về uy thế lẫn thiên uy đi kèm.","nguon":["@c0467"]},{"id":"tam-chuyen-kim-tien-luc","name":"Tam chuyển kim tiên lực","loai":"khac","loaiLabel":"Lực lượng đặc thù","phamCap":"Kim tiên lực","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cỗ tiên lực đặc dị trong cánh tay trái Vương Lâm, có thể thả ra lưu chuyển toàn thân để chống lại sức hút và thiên uy của Tiên thuật.","detail":"Khi thiên uy của Dẫn Tiên thuật khiến tiên lực vốn có hỗn loạn, Vương Lâm vận tam chuyển kim tiên lực từ cánh tay trái cho lưu chuyển toàn thân, khống chế không để nó hòa lẫn với tiên lực thường, nhờ đó đứng vững lại. Riêng cỗ kim tiên lực này không bị Dẫn Tiên thuật dẫn dắt, cho thấy nó khác biệt với tiên lực thông thường.","nguon":["@c0467"]},{"id":"kim-tien-luc","name":"Kim tiên lực","loai":"khac","loaiLabel":"Linh lực tu luyện","phamCap":"Tiên lực","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Linh lực kim sắc Vương Lâm vận luyện, vận chuyển theo vòng để chống chịu áp lực và khôi phục.","detail":"Trong khảo nghiệm áp lực tại đại thọ Thiên Vận Tử, Vương Lâm vận chuyển kim tiên lực ba vòng để khôi phục sắc mặt sau khi trụ vững, biểu hiện vượt trội so với đa số đệ tử.","nguon":["@c0468"]},{"id":"yeu-anh-dao","name":"Yêu ảnh đạo","loai":"than-thong","loaiLabel":"Thần thông / Đạo","phamCap":"Đạo bản mệnh","hePhai":"Thiên Vận Tông","soHuu":["Triệu Hân Mộng"],"blurb":"Đạo bản mệnh của Triệu Hân Mộng; chỉ cần xem qua một thần thông của đối thủ tu vi không cao hơn nàng là bắt chước được một phần.","detail":"Yêu ảnh đạo là con đường tu hành của Tứ sư tỷ Triệu Hân Mộng. Đặc tính cốt lõi: chỉ cần nàng nhìn qua một thần thông của đối thủ — với điều kiện tu vi đối phương không cao hơn nàng — là có thể mô phỏng lại một phần (không hoàn toàn) thần thông đó. Nhờ đó nàng sáng chế ra Tử Ma thủ từ Hoá Ma chỉ của Vương Lâm.","nguon":["@c0469"]},{"id":"tu-ma-thu","name":"Tử Ma thủ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Vận Tông","soHuu":["Triệu Hân Mộng"],"blurb":"Thần thông Triệu Hân Mộng tự sáng chế bằng cách mô phỏng Hoá Ma chỉ của Vương Lâm qua Yêu ảnh đạo.","detail":"Triệu Hân Mộng vận Tử Ma thủ bằng cách bấm quyết điểm về phía trước: vô số tinh quang màu tím vờn quanh người rồi ngưng tụ bao bọc tay phải, sau đó nàng vỗ tay đẩy tử quang gào rít lao tới đối thủ. Thần thông này được mô phỏng một phần từ Hoá Ma chỉ của Vương Lâm thông qua Yêu ảnh đạo.","nguon":["@c0469"]},{"id":"hoang-tuyen-chi","name":"Hoàng tuyền chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Sát chiêu","phamCap":"","hePhai":"","soHuu":["Vương Lâm","Tư Đồ Nam"],"blurb":"Sát chiêu thứ ba và cuối trong ba sát chiêu của Tư Đồ Nam, thi triển bằng cách tiêu tan sinh mạng để mượn uy lực Hoàng tuyền.","detail":"Sát chiêu cuối trong ba sát chiêu Tư Đồ Nam truyền cho Vương Lâm. Muốn học phải nắm Hoàng tuyền thăng khiếu quyết, thông qua sinh mệnh tiến nhập Hoàng tuyền, biến chuyển sống-chết mà cảm ngộ. Tư Đồ Nam năm xưa giữa sống chết ở Hoàng tuyền kết hợp một bản hạ phẩm tiên thuật tàn khuyết mà bắt chước tạo ra, uy lực thua tiên thuật tàn khuyết thật không nhiều. Khi điểm ra, tiên lực không dao động, khí tức sinh mạng tiêu tan, trời tối sầm sét đánh, một bức tranh cuốn sơn thủy biểu thị Hoàng tuyền hiện ra rồi bụi khí dung hợp ngưng thành chỉ kích, kèm theo Sinh tử luân hồi ý cảnh. Đòi hỏi Anh Biến hậu kỳ trở lên mới dùng an toàn; Anh Biến sơ kỳ dùng sẽ bị cắn trả, Anh Biến trung kỳ miễn cưỡng dùng nhưng không thể dùng hết, chỉ Vấn Đỉnh mới tùy tâm thi triển.","nguon":["@c0471"]},{"id":"tu-sac-quang-cau-tran-dao","name":"Tử sắc quang cầu","cn":"","loai":"bi-thuat","loaiLabel":"Thuật phòng ngự","phamCap":"","hePhai":"","soHuu":["Trần Đào"],"blurb":"Thuật phòng ngự tạo các quang cầu màu tím quanh thân, nổ tung khi bị tấn công.","detail":"Trần Đào bấm quyết tạo các quang cầu màu tím vây quanh thân để chống hắc mang của Hồn thú; các quang cầu nổ tung khi bị tấn công, nhưng vẫn khiến hắn chịu tổn thương và kêu đau.","nguon":["@c0471"]},{"id":"van-tam-chi-canh","name":"Vấn Tâm chỉ cảnh","aliases":["Vấn Tâm"],"loai":"khac","loaiLabel":"Cảnh giới tu tâm","phamCap":"Cực cao","hePhai":"Hệ tu tâm","soHuu":["Vương Lâm"],"blurb":"Cảnh giới tu tâm khi tâm lạnh tới mức vạn vật băng hàn cũng không thể đông lạnh thân tâm, ý chí bất khuất vờn quanh thân.","detail":"Một tầng cảnh giới tu tâm bộc lộ trong Toái Tiên chi địa: khi hàn khí cực dày xông vào kinh mạch nhưng bị thần thức từ nguyên thần quét lui, người tu nhận ra cái lạnh ngoại giới không lạnh bằng cái lạnh trong tâm mình. Sự lạnh lẽo trong lòng cùng ý chí bất khuất hợp lại thành then chốt vượt khảo nghiệm. Vương Lâm nhờ đó lĩnh ngộ Luân hồi đạo là đại Vô tình đạo và hiện Luân hồi Hoạ trục sau lưng. Thiên Vận Tử còn nghi vấn liệu tu thêm vạn năm có thể đột phá tới cảnh giới thứ ba sau Vấn Tâm.","nguon":["@c0472"]},{"id":"luan-hoi-dao","name":"Luân hồi đạo","aliases":["Luân hồi ý cảnh"],"loai":"khac","loaiLabel":"Ý cảnh đại đạo","phamCap":"Đại đạo","hePhai":"Hệ Luân hồi","soHuu":["Vương Lâm"],"blurb":"Đại đạo Vương Lâm lĩnh ngộ chính là đại Vô tình đạo, hiện thành Luân hồi Hoạ trục.","detail":"Tại Toái Tiên chi địa, Vương Lâm lĩnh ngộ rằng Luân hồi đạo chính là đại Vô tình đạo. Ý cảnh hiện thành Luân hồi Hoạ trục — bức tranh sơn thủy chỉ có hai màu đen trắng — xuất hiện sau lưng và có thể thu nhỏ xoay quanh đỉnh đầu, bao bọc toàn thân bằng một lực lượng kỳ dị. Trong trận đấu trước đó, ý cảnh này từng biến thành đạo Hoàng tuyền chỉ thứ hai công kích Trần Đào.","nguon":["@c0472"]},{"id":"chan-huyen-phap","name":"Chân huyễn pháp","loai":"bi-thuat","loaiLabel":"Huyễn thuật che giấu","phamCap":"Cao","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử"],"blurb":"Pháp môn của Thiên Vận Tử tạo hai ngọn núi giả bên cạnh ngọn thật; tu vi Anh Biến trung kỳ rất khó nhìn ra.","detail":"Huyễn thuật che giấu của Thiên Vận Tử đặt tại Tổng tông ba ngọn núi: ngọn giữa là thật phủ bạch tuyết Cửu U chi hàn, còn hai sườn núi đen hai bên là giả do Chân huyễn pháp dựng nên. Ngọn giả bên trái có tuyết đen mà không kèm hàn khí (lộ vẻ quỷ dị), ngọn phải mơ hồ có sức sống. Tu sĩ Anh Biến trung kỳ nhìn ra được điểm giả là chuyện hiếm có, nên Thiên Vận Tử kinh ngạc tán thưởng khi Vương Lâm giải đúng.","nguon":["@c0472"]},{"id":"y-canh-nhap-the","name":"Ý cảnh nhập thể","cn":"","loai":"than-thong","loaiLabel":"Cảnh giới lĩnh ngộ","phamCap":"Đỉnh cao lĩnh ngộ Anh Biến kỳ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bước cụ thể hóa ý cảnh thành thực chất, dung một tia cảm ngộ vào tâm cảnh để vượt cực hạn và mở đường lên Vấn Đỉnh.","detail":"Ý cảnh là sự c�� thể hóa cảm ngộ qua sơ, trung, hậu kỳ; dưới cảm ngộ của tu sĩ Anh Biến kỳ thì ý cảnh hoàn toàn biến thành thực chất, cần một quá trình chứ không tức thời. Ý cảnh nhập thể là dung một tia cảm ngộ vào tâm cảnh để vượt qua cực hạn của bản thân, biểu hiện thành việc bước được càng nhiều bước trên nền tảng có sẵn. Vương Lâm nhờ đó bước hai mươi bảy bước, mở con đường tiến lên Vấn Đỉnh.","nguon":["@c0473"]},{"id":"than-thong-bay-mau-toi-hy-khau","name":"Thần thông bảy màu (Tối hỷ khẩu thất thải)","aliases":["Tối hỷ khẩu thất thải","Thần thông bảy màu"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấm pháp thần thông","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử"],"blurb":"Cấm pháp dùng bảy màu công kích; ánh sáng màu tím trong bảy màu có thể hoá vạn vật thành hư vô.","detail":"Một trong 3600 đạo Cấm pháp thần thông trong thế giới bảy màu. Thiên Vận Tử bắn ánh sáng bảy màu công kích, trong đó màu tím khiến mọi thứ hoá thành hư vô. Vương Lâm xem hết hơn phân nửa 3600 thần thông và coi đây là pháp thuật kỳ diệu, đáng sợ nhất, gần như định chọn nó trước khi chú ý tới Thiên Vận Tử áo xám.","nguon":["@c0474"]},{"id":"sat-luc-tien-quyet","name":"Sát Lục Tiên quyết","loai":"cong-phap","loaiLabel":"Tiên quyết","phamCap":"Tiên quyết (mô phỏng Tiên thuật)","hePhai":"Thiên Vận Tử áo xám","soHuu":["Thiên Vận Tử áo xám"],"blurb":"Tiên quyết bắt chước từ một loại Tiên thuật vô danh, dựa vào giết chóc đoạt sinh lực ngưng kết thành Sinh chi lạc ấn phòng thủ.","detail":"Không phải Tiên thuật chân chính mà bắt chước từ một loại Tiên thuật vô danh. Người tu dựa vào giết chóc để đoạt sinh lực, sinh lực vờn quanh thân ngưng kết thành Sinh chi lạc ấn; lạc ấn càng nhiều thì phòng thủ càng mạnh — thân Thiên Vận Tử áo xám được hàng tỷ lạc ấn thủ hộ, dù Thiên Vận Tinh sụp đổ cũng bình yên vô sự. Điều kiện học là ‘xuất thủ không lưu người sống’; được cho là rất xứng với Sinh tử Luân hồi ý cảnh của Vương Lâm, song Vương Lâm từ chối học.","nguon":["@c0474"]},{"id":"sinh-chi-lac-an","name":"Sinh chi lạc ấn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật hộ thể","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ấn pháp hộ thể của Vương Lâm, có tác dụng phòng hộ rất lớn.","detail":"Sinh chi lạc ấn là một ấn pháp hộ thể Vương Lâm sở hữu, được hắn nhắc tới khi ngẫm về các thủ đoạn phòng thân; tác dụng phòng hộ rất lớn.","nguon":["@c0476"]},{"id":"thuat-thuan-di-ngan-mang","name":"Pháp thuật thuấn di ngân mang","loai":"than-thong","loaiLabel":"Thần thông di chuyển","phamCap":"Cao cấp","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dịch chuyển khoảng cách cực lớn bằng cách bước trên không trung như lên bậc thang trời.","detail":"Vương Lâm vẽ trận lên không trung, thân thể nổi ngân mang, bước từng bước như leo bậc thang trời rồi dịch chuyển khoảng cách cực lớn; mỗi lần thi triển tạo dị tượng ngân mang phủ khắp bầu trời như một mặt trời bạc. Mười bước là cực hạn hắn chịu được; khi hiện thân sắc mặt tái nhợt, phải dùng đan dược mới hồi phục.","nguon":["@c0478"]},{"id":"sat-luc-tien-quyet-tu-luyen","name":"Sát Lục Tiên quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Tiên quyết","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Công pháp thu hồi sinh lực ngay trong giết chóc; mỗi lần giết một sinh vật thu được một đạo bụi khí nghi là sinh lực.","detail":"Sát Lục Tiên quyết là công pháp Vương Lâm tu luyện trong Tùng Mãng Sơn mạch, cốt lõi là ‘ở trong giết chóc thu hồi sinh lực’. Mỗi lần giết yêu thú hay sinh vật, hắn thu được một đạo bụi khí nhạt quanh quẩn đầu ngón trỏ phải, lâu không tan, càng giết nhiều càng nồng đậm. Vương Lâm chưa chắc chắn bụi khí này có đúng là sinh lực hay không, và đang suy diễn cách đem sức sống thu được hóa thành Sinh chi lạc ấn. Hắn dùng các yêu thú mạnh, kể cả hai lão Anh Biến sơ kỳ của Đại La Kiếm Tông, làm thí luyện giả.","nguon":["@c0479"]},{"id":"sinh-chi-lac-an-suy-dien","name":"Sinh chi lạc ấn","cn":"","loai":"bi-thuat","loaiLabel":"Ấn pháp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ấn pháp Vương Lâm đang suy diễn, đem sức sống (sinh lực thu được từ Sát Lục Tiên quyết) hóa thành ấn.","detail":"Sinh chi lạc ấn là chiêu thức Vương Lâm đang suy diễn trong quá trình tu luyện Sát Lục Tiên quyết: lấy sinh lực thu được qua giết chóc rồi hóa thành một loại ấn. Đến chương này quá trình suy diễn còn dang dở, là hướng phát triển của hắn về công pháp này.","nguon":["@c0479"]},{"id":"kiem-phong-chi-cam","name":"Kiếm phong chi cấm","loai":"bi-thuat","loaiLabel":"Cấm thuật / Phong ấn","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Thạch Phương"],"blurb":"Cấm thuật phong ấn của Thạch Phương, phát động qua ngọc giản đỏ để giam giữ cả vùng sơn cốc.","detail":"Thạch Phương lấy ngọc giản màu đỏ, kết kiếm chỉ hô “Mở!” rồi “Phong!”. Ngọc giản bay vào sơn cốc tan thành vô số sợi tơ đỏ đan thành tấm lưới đỏ bao vây mục tiêu, kết hợp với kỳ hiệu điện quang tạo thành phong ấn nghiêm mật; dùng để phong ấn nam tử áo trắng cùng đàn Cửu Lê trùng trong phạm vi mấy trượng.","nguon":["@c0481"]},{"id":"tu-chuyen-ham-tien-luc","name":"Tứ chuyển hàm tiên lực","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên lực Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Chiêu thức dùng kính tản tia sáng ngưng tụ kim sắc lốc xoáy chứa tiên lực, vỗ ra phá tan kiếm quang đối thủ.","detail":"Vương Lâm khuếch tán tiên lực bao phủ sơn cốc, dùng một chiếc kính tản vô vàn tia sáng tụ thành kim sắc lốc xoáy trong lòng bàn tay rồi hô “Tứ chuyển, hàm tiên lực!”, vỗ ra phá tan kiếm quang của Thạch Phương, gây nứt vỡ địa hình, vách núi sụp đổ.","nguon":["@c0483"]},{"id":"doat-xa-sieu-toc","name":"Đoạt xá siêu tốc","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Thạch Phương","soHuu":["Thạch Phương"],"blurb":"Phương pháp đoạt xá cực nhanh, gần như hoàn thành chiếm thân và khôi phục thần trí tức thì.","detail":"Khác với đoạt xá thường mất rất lâu để dung hợp (Tư Đồ Nam đoạt kim cũng cần hơn một ngày), bí pháp của Thạch Phương cho phép xuyên phi kiếm qua mi tâm vật chủ rồi đoạt xá gần như tức khắc, hồi phục thần trí ngay khiến Vương Lâm kinh ngạc. Thạch Phương ghi lại vào ngọc giản, kèm thần thông mượn xử nữ chữa thương.","nguon":["@c0483"]},{"id":"phuong-phap-dieu-hoa-do-ti","name":"Phương pháp điều hoà (ký ức Đồ Ti)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bí thuật Cổ Thần","hePhai":"Ký ức Cổ Thần Đồ Ti","soHuu":["Vương Lâm"],"blurb":"Thủ pháp cổ quái thừa kế trong ký ức Đồ Ti, dùng Chú ngôn ép linh quả héo rũ thành linh căn cấp tốc thay vì chờ chu kỳ tự nhiên.","detail":"Người thi triển kết thủ ấn cổ quái bằng tay trái (không phải pháp quyết của tu sĩ) rồi thốt Chú ngôn như tiếng ‘Một!’, phóng ánh sáng vàng làm nổ lần lượt các ngọc giản dẫn đặt cạnh hoa, ép hoa, quả và cành cây héo rũ tan thành chất lỏng dung nhập xuống đất để hình thành linh căn dưới gốc. Cổ Thần nguyên bản dùng xương cốt yêu thú làm vật dẫn; Vương Lâm thay bằng ngọc giản nên hiệu quả kém hơn, thu được bốn linh căn thay vì năm.","nguon":["@c0484"]},{"id":"tam-phan-than-thuc-thuat","name":"Tam phân thần thức thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Lão già thấp người (Trưởng lão Đại La Kiếm Tông)"],"blurb":"Bí thuật cho phép người tu tái sinh ba lần sau khi bị giết.","detail":"Công pháp do lão già thấp người của Đại La Kiếm Tông tu luyện, cho phép tái sinh tối đa ba lần. Sau khi bị loan đao của Vương Lâm xuyên đầu, lão dùng lần tái sinh cuối cùng: khoảng ba nén nhang sau lão mở mắt, vết thương mi tâm tự khép lại. Tuy nhiên ngay sau đó lão bị khí xám Sát lục tiên quyết truy sát hút sạch sức sống, không còn cơ hội tái sinh.","nguon":["@c0485"]},{"id":"yeu-linh-quan-dinh","name":"Yêu Linh quán đính","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Ban thưởng","phamCap":"","hePhai":"Đông Hải Yêu Linh chi môn","soHuu":[],"blurb":"Phần thưởng quý giá của Đông Hải Yêu Linh chi môn: cưỡng ép tu vi tăng một cảnh giới và hỗ trợ đột phá Vấn Đỉnh.","detail":"Chỗ tốt chân chính khi đi ra khỏi Đông Hải Yêu Linh chi môn là được Yêu Linh quán đính một lần. Quán đính cưỡng ép tu vi tăng một cảnh giới; nếu đúng lúc Vấn Đỉnh thì cơ hội đạt Vấn Đỉnh tăng vô số lần; đã đạt Vấn Đỉnh thì bước thêm một bước; tới Vấn Đỉnh hậu kỳ thì sau quán đính có thể đột phá vào Âm Dương nhị ý, thọ mấy vạn năm, thân thể bất diệt. Tục truyền nếu chỉ một người duy nhất đi ra thì còn được ban một loại hạ phẩm tiên thuật hoàn chỉnh chưa từng xuất hiện.","nguon":["@c0485"]},{"id":"huyet-cong-dieu-tinh-hai","name":"Huyết Công","cn":"","loai":"cong-phap","loaiLabel":"Ma công","phamCap":"Không rõ","hePhai":"Huyết hệ","soHuu":["Huyết Tổ Diêu Tinh Hải","Diêu Tích Tuyết"],"blurb":"Ma công huyết hệ của Huyết Tổ Diêu Tinh Hải, thi triển trong lần thứ bảy khiêu chiến Thiên Vận Tử khiến người kinh sợ.","detail":"Công pháp trấn gia của Huyết Tổ, tu luyện bằng cách nạp huyết trên Huyết Tinh. Huyết Tổ đem toàn bộ công pháp này truyền cho con gái Diêu Tích Tuyết rồi nghịch thiên cải mệnh cho nàng.","nguon":["@c0486"]},{"id":"tran-phap-tinh-khong-huyen-uyen","name":"Trận pháp tinh không (Huyền Uyên phái)","cn":"","loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"","hePhai":"Huyền Uyên phái","soHuu":["Tôn Vân Sơn"],"blurb":"Trận pháp truyền tống trong tinh không của Huyền Uyên phái, dùng để di chuyển tới Đông Hải Yêu Linh.","detail":"Đại trận truyền tống đặt trong tinh không; khi khởi động cần dùng lượng lớn tinh thạch và tiên ngọc, đồng thời mấy trăm đệ tử cùng vận chuyển linh lực dung nhập. Khi bùng nổ, trận tạo ra một cầu vồng cao trăm trượng đâm thẳng vào tầng mây, đưa người dùng di chuyển tới cửa Đông Hải Yêu Linh ở tinh không phía đông.","nguon":["@c0487"]},{"id":"bi-thuat-nhot-kiem-hon-kiem-ton","name":"Bí thuật nhốt kiếm hồn (Kiếm Tôn)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Kiếm Tôn"],"blurb":"Bí thuật Lăng Thiên Hậu dùng để nhốt đạo kiếm hồn của nữ quân tiên giới vào trong Đông Hải Yêu Linh.","detail":"Năm xưa Kiếm Tôn bị một đạo kiếm hồn uy lực kinh người làm phiền không dứt; do không khống chế được, lão dùng bí thuật này nhốt kiếm hồn lại trong Đông Hải Yêu Linh, và còn định mượn thủy triều năm nghìn năm một lần để hút nó chìm sâu vĩnh viễn.","nguon":["@c0487"]},{"id":"am-duong-hu-thuc-nhi-y","name":"Âm Dương Hư Thực Nhị Ý","cn":"","loai":"khac","loaiLabel":"Ý cảnh / điều kiện đột phá","phamCap":"","hePhai":"","soHuu":[],"blurb":"Lĩnh hội liên quan tới việc đột phá tầng hạn chế thọ nguyên và tiến vào Đông Hải Yêu Linh.","detail":"Là điều kiện then chốt để vượt qua tầng hạn chế thọ nguyên: tu sĩ không lĩnh hội tiến vào được thì thọ nguyên không thăng hoa, không sống quá năm nghìn năm. Việc tiến vào Đông Hải Yêu Linh cũng liên quan tới nhị ý này.","nguon":["@c0487"]},{"id":"thuong-pham-tien-thuat","name":"Thượng phẩm tiên thuật (hoàn chỉnh)","cn":"","loai":"khac","loaiLabel":"Tiên thuật","phamCap":"Thượng phẩm","hePhai":"Tu Chân Liên Minh","soHuu":[],"blurb":"Tiên thuật cấp cao nhất, loại hoàn chỉnh được Tu Chân Liên Minh treo làm phần thưởng truy tìm hạt châu.","detail":"Một bộ thượng phẩm tiên thuật hoàn chỉnh là phần thưởng lớn chưa từng có mà Tu Chân Liên Minh đưa ra từ khi thành lập, treo cho ai tìm được hạt châu mấy vạn năm trước. Theo manh mối Tham Lang nắm được, loại tiên thuật hoàn chỉnh trong Tu Chân Liên Minh tuyệt đối không quá mười bộ, cho thấy mức độ trân quý và hiếm có của nó.","nguon":["@c0488"]},{"id":"than-thong-anh-mat-khi-xam","name":"Thần thông ánh mắt khí xám (Ba đạo ấn ký)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hệ Cổ Thần khí xám","soHuu":["Vương Lâm"],"blurb":"Thần thông gắn với khí xám hệ Cổ Thần của Vương Lâm: ba đạo ấn ký trên mi tâm cấp lực cho ánh mắt để xuyên phá thứ ngăn cản thần thức và tầm nhìn.","detail":"Khi vận thần thông, ba đạo khí xám hiện trên mi tâm Vương Lâm rồi hóa thành ba ấn ký phức tạp, theo hai mắt cuộn thành vòng tròn mịn khiến đồng tử phát luồng sáng như ánh trăng, vệt sáng dài chừng nửa thước. Ánh mắt biến thành thần quang xuyên qua hư vô, có thể đuổi theo và đâm thủng những thứ chặn cả thần thức lẫn ánh mắt thăm dò; khí xám hóa thành tơ chui vào đồng tử tiếp sức liên tục. Cái giá là đôi mắt đỏ bừng, chảy nước mắt lẫn máu, tim đau dữ dội. Tại cửa Đông Hải Yêu Linh, ánh mắt hắn cuối cùng nổ tung phá vỡ tầng tầng hồng quang để nhìn rõ khối lệnh bài bên trong.","nguon":["@c0490"]},{"id":"tran-phap-an-giau-khi-tuc-son-coc","name":"Trận pháp ẩn giấu khí tức sinh mạng (sơn cốc)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thượng cổ","hePhai":"Tu sĩ thời kỳ thượng cổ","soHuu":[],"blurb":"Trận pháp do tu sĩ thượng cổ dùng đại thần thông bố trí ngoài sơn cốc, ẩn giấu mọi khí tức sinh mạng và phòng vệ bằng khí xanh thôn phệ.","detail":"Bố trí bên ngoài một sơn cốc trong vùng Đông Hải yêu linh, đã tồn tại vô số năm. Trận pháp ẩn giấu mọi khí tức sinh mạng nên rất khó phát hiện nếu không ở thật gần. Có chức năng phòng vệ: khi bị tấn công liền phóng ra luồng khí xanh thôn phệ linh quang, kẻ mạnh xông vào sẽ bị giết sạch. Thủ pháp hoàn toàn khác với tu sĩ liên minh tu chân; Vương Lâm trong thời gian ngắn không thể phá giải.","nguon":["@c0492"]},{"id":"thuong-co-tran-phap-son-coc","name":"Thượng cổ trận pháp (cổ cấm chế sơn cốc)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Bộ tộc sơn cốc","soHuu":["Âu Dương Hoa"],"blurb":"Trận pháp thượng cổ bảo vệ sơn cốc bộ tộc Âu Dương Hoa, có thể hút kéo vạn vật ngưng thành hư ảnh người công kích.","detail":"Cổ cấm chế bao quanh sơn cốc, chống đỡ thanh quang và cấm khí công phá. Khi bị kích phát mạnh, trận vận chuyển dùng thanh quang dày đặc bao phủ vạn vật ngoài cốc, hút kéo sinh lực mọi thứ về trong cốc, ngưng tụ thành một bóng người hư ảo màu xanh cao mấy trượng, mờ ảo không rõ tướng mạo, dùng để giết kẻ địch và lấy hồn phách tế yêu linh. Vương Lâm phải nghiên cứu cổ cấm chế hồi lâu mới tìm ra cách phá.","nguon":["@c0493"]},{"id":"cam-phap-chi-mau","name":"Cấm pháp chi mâu","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Cấm pháp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp thuật Vương Lâm triệu cấm khí đen ngưng tụ thành trường mâu ba trượng, vung ra hóa tia chớp đen công kích.","detail":"Vương Lâm bắt quyết hô “Cấm pháp chi mâu”, triệu cấm khí màu đen như du long từ chân trời bay tới kèm tiếng gào khóc, ngưng tụ trên tay thành một thanh trường mâu đen dài ba trượng — gợn sóng đen, tiếng sấm rền, u quang ở lưỡi mâu. Vung mâu hóa thành tia chớp đen lao thẳng vào mục tiêu, dùng nghênh chiến hư ảnh xanh do trận pháp sơn cốc tạo ra.","nguon":["@c0493"]},{"id":"thuong-co-cam-che-co-than","name":"Thượng cổ cấm chế của cổ thần","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thượng cổ","hePhai":"Cổ thần","soHuu":["Vương Lâm"],"blurb":"Sở học cấm chế thượng cổ Vương Lâm kế thừa từ cổ thần năm xưa, ghép phù văn thành tổ hợp cấm chế để phá trận.","detail":"Loại thủ pháp ra đời từ thời cực xa xưa, ngay cả thượng cổ tu sĩ cũng chỉ nắm được chứ không sáng tạo thêm. Khi vận dụng, các phù văn hợp-tản-hợp như vòng tròn luân hồi, tách thành mấy chục cấm chế giống nhau rồi tổ hợp lại phóng ra. Tại sơn cốc Âu Dương Hoa, Vương Lâm tính toán dần từ năm mươi bảy lên tám mươi ba tổ hợp cấm chế, phóng các đạo phù văn yêu dị từ trong hai mắt tạo sóng gợn hủy diệt thanh mang, phá tan lồng thanh quang thượng cổ.","nguon":["@c0494"]},{"id":"truong-mau-cam-khi","name":"Trường mâu cấm khí","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cấm khí của Vương Lâm biến hóa thành trường mâu phá không lao nhanh như sấm sét, chủ yếu dùng để câu giờ.","detail":"Cấm khí Vương Lâm biến ảo thành hình trường mâu, lao đi cực nhanh đánh vào thanh ảnh của trận pháp. Mục đích chính không phải sát thương mà là câu giờ để hắn tính toán cấm chế phá trận. Tại sơn cốc Âu Dương Hoa, trường mâu bị lồng thanh quang phân thành hai và hủy đi, nhưng Vương Lâm không tiếc vì đã đạt mục đích câu giờ.","nguon":["@c0494"]},{"id":"tran-phap-son-coc","name":"Trận pháp sơn cốc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trận pháp cổ bao quanh sơn cốc tộc Âu Dương Hoa, tồn tại từ vô số năm trước, bảo vệ tộc nhân khỏi yêu linh.","detail":"Trận pháp đã có mặt từ trước khi Hoàng Long dẫn tổ tiên Âu Dương Hoa đến định cư, không ai nhớ nguồn gốc. Lực lượng bảo vệ của trận từng dần tiêu tán khiến tộc nhân lo bại lộ dưới đêm yêu linh; Vương Lâm chỉ cần giơ tay điểm lên hư không tạo một đợt sóng gợn như tấm vải là khôi phục lại, làm tốc độ tiêu tán chậm dần rồi ngừng hẳn.","nguon":["@c0495"]},{"id":"hap-thu-yeu-luc","name":"Hấp thu yêu lực","cn":"","loai":"luyen-the","loaiLabel":"Luyện hóa","phamCap":"","hePhai":"Nơi yêu linh","soHuu":["Vương Lâm"],"blurb":"Cách hấp thu khí tức yêu lực từ ngọc yêu linh: khí tức cực lạnh chạy theo các khớp xương chứ không qua kinh mạch, tụ tại đan điền thành tinh thể.","detail":"Khi Vương Lâm hấp thu ngọc yêu linh, một khí tức cực lạnh theo tay phải chui vào cơ thể, không đi trong kinh mạch như linh lực thông thường mà chạy dọc các khớp xương, cuối cùng tụ lại đan điền hóa thành tinh thể cỡ hạt gạo, khí tức xoay tròn như tinh vân. Thứ khí tức trắng này trông như tiên lực nhưng trong vẻ ôn hòa lại lộ sự yêu dị cực kỳ; sau khi hấp thu, toàn thân Vương Lâm có biến hóa cực kỳ rõ ràng, gợi mở một con đường biến hóa mới.","nguon":["@c0496"]},{"id":"tran-phap-ho-lo-coc","name":"Trận pháp Hồ Lô Cốc","cn":"","loai":"khac","loaiLabel":"Trận pháp phòng thủ","phamCap":"","hePhai":"Hồ Lô Cốc","soHuu":["Âu Dương Hoa"],"blurb":"Trận pháp bảo vệ thung lũng Hồ Lô Cốc, tỏa thanh quang chống sóng yêu khí trong đêm Yêu linh săn mồi.","detail":"Trận pháp bao bọc thung lũng Hồ Lô Cốc, mỗi khi đêm Yêu linh săn mồi (ba tháng một lần) ập tới thì mở thanh quang chống cự sóng yêu khí cuồng nộ. Trận do Âu Dương Hoa giơ tay niệm chú duy trì. Trong chương này trận đã bị Vương Lâm tiêu hao hơn nửa nên Âu Dương Hoa không chắc chống nổi; khi một vật nặng va vào, nhiều chỗ trận vỡ tan.","nguon":["@c0497"]},{"id":"dia-diet-chi-hoa","name":"Địa diệt chi hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông hỏa hệ","phamCap":"","hePhai":"","soHuu":["La mỗ"],"blurb":"Hỏa thuật hắc y nam tử triệu trên lòng bàn tay trái, ngọn lửa đen che phủ trời đất.","detail":"La mỗ bấm thần chú, lòng bàn tay trái hiện ngọn lửa đen, hô “Địa diệt chi hỏa, nhiên tận hư vô”. Ngọn lửa bay lên không trung che phủ trời đất, hóa thành sáu con rồng lửa (Viêm Long) gầm vang như Thiên Lôi xông tới cắn xé đối phương.","nguon":["@c0498"]},{"id":"kiem-toai-la-mo","name":"Kiếm toái","cn":"","loai":"kiem-quyet","loaiLabel":"Cấm thuật kiếm","phamCap":"","hePhai":"","soHuu":["La mỗ"],"blurb":"Cấm thuật khiến tế kiếm vỡ vụn thành vô số mảnh nổ tung lao về đối phương.","detail":"La mỗ quát “Kiếm toái”, tế kiếm lập tức vỡ thành vô số mảnh nhỏ nổ tung, đồng loạt lao về phía Vương Lâm như mưa kiếm sát thương.","nguon":["@c0498"]},{"id":"ma-cam","name":"Ma cấm","loai":"bi-thuat","loaiLabel":"Cấm thuật ma đạo","hePhai":"Ma đạo","soHuu":["La mỗ (Hắc y nhân)"],"blurb":"Cấm thuật ma đạo hút khói đen vào ngực, biến tay trái thành mười Quỷ ảnh quái dị để công kích.","detail":"Thi triển bằng cách ấn tay vào ngực hút khói đen vào người, chịu đau tột độ tới mức da nổi gân xanh mụn sần, mắt đầy tơ máu rồi gào thét chấn động (nguyên thần cảm được dù không thành tiếng), đánh văng vật chất quanh mình tạo khoảng trống. Khẩu quyết “Ma cấm, thiên quỷ đệ tứ tôn, hiện!” khiến lực kỳ dị từ ngực chảy qua cánh tay, tay trái mọc xúc tu biến thành mười Quỷ ảnh đen nhe răng cười, mắt tràn hàn quang, có thể nuốt kiếm quang. Cấm thuật gây phản phệ rõ rệt lên người thi triển.","nguon":["@c0499"]},{"id":"huyet-sac-ngu-sat","name":"Huyết sắc ngũ sát","loai":"bi-thuat","loaiLabel":"Cấm pháp phong ấn","soHuu":["La mỗ (Hắc y nhân)"],"blurb":"Cấm pháp tạo năm điểm đỏ đan thành lưới năm sao phong ấn pháp bảo của kẻ thù.","detail":"Năm ngón tay tạo năm điểm đỏ di động, đan thành lưới năm sao, hô “Cấm” để phong ấn pháp bảo đối phương. Trong trận với Vương Lâm, lần đầu thất bại khi định phong ấn Côn Cực Tiên: roi tiên phát hắc mang lan tới tay phải khiến tay bốc khói trắng, đau đớn.","nguon":["@c0499"]},{"id":"phong-than-chu-goi-gio","name":"Phong (thần chú gọi gió)","loai":"than-thong","loaiLabel":"Thần chú","soHuu":["Vương Lâm"],"blurb":"Thần chú bấm tay niệm chú gọi gió quái lạ và mây đen phá màn sương độc.","detail":"Vương Lâm bấm tay niệm chú, gọi gió quái lạ cùng mây đen phá vỡ màn sương độc do Hắc y nam tử phun ra, đồng thời hóa thân thành làn mây thoát ra ngoài.","nguon":["@c0499"]},{"id":"hoa-ma-chi-tam-sat","name":"Hóa ma chỉ","loai":"than-thong","loaiLabel":"Thần thông / Sát chiêu","phamCap":"Sát chiêu trục","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Chiêu thứ hai trong Tam thức sát chiêu của Vương Lâm — tiên lực nghịch chuyển ngưng tụ thành ma khí ở đầu ngón trỏ.","detail":"Hóa ma chỉ là chiêu thứ hai trong bộ Tam thức sát chiêu của Vương Lâm. Khi thi triển, tiên lực bị nghịch chuyển và chuyển hóa, ngưng tụ thành ma khí dày đặc ở đầu ngón trỏ; ma khí khuếch tán mãnh liệt, ngón tay trở nên linh hoạt sắc bén. Vương Lâm từng dùng chiêu này đấu với Tử hệ lão Tứ. Khi hai Hóa ma chỉ (của Vương Lâm và khói đen của đối thủ) va chạm sẽ hình thành tiểu cầu chứa điện quang như Thiên kiếp tiên lôi.","nguon":["@c0500"]},{"id":"tam-thuc-sat-chieu","name":"Tam thức sát chiêu","loai":"cong-phap","loaiLabel":"Bộ sát chiêu","phamCap":"Sát chiêu trục","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Bộ ba sát chiêu của Vương Lâm; Hóa ma chỉ là chiêu thứ hai.","detail":"Tam thức sát chiêu là bộ ba sát chiêu Vương Lâm thường dùng trong giao đấu sinh tử, trong đó Hóa ma chỉ là chiêu thứ hai. Bộ chiêu này từng được Vương Lâm thi triển trong các trận sinh tử và lưu lại ấn tượng mạnh nơi người xem.","nguon":["@c0500"]},{"id":"sinh-chi-lac-an-than-thong","name":"Sinh chi lạc ấn","loai":"than-thong","loaiLabel":"Thần thông / Ấn ký","phamCap":"Thần thông trục","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ký hiệu màu xám trên mi tâm lan bao trùm toàn thân, giúp xuyên qua khói độc vô hại và di chuyển nhanh như điện.","detail":"Khi kích hoạt, một ký hiệu màu xám trên mi tâm V��ơng Lâm lan rộng bao trùm toàn thân. Trạng thái này cho phép hắn xuyên qua khói độc và sương đen của đối thủ mà vô hại, đồng thời di chuyển nhanh như điện để truy sát Hắc y nam tử.","nguon":["@c0500"]},{"id":"cuu-tu-chan-ngon","name":"Cửu Tự Chân Ngôn","loai":"bi-thuat","loaiLabel":"Chân ngôn khống chế","phamCap":"Truyền thừa tiên nhân","hePhai":"Di sản tiên nhân","soHuu":["Vương Lâm"],"blurb":"Chín chữ chân ngôn từ Ngọc giản của tiên nhân, dùng khống chế Hồn thú trong Xạ Thần Xa.","detail":"Cửu Tự Chân Ngôn gồm chín chữ chân ngôn Vương Lâm học được từ Ngọc giản của một vị tiên nhân. Chân ngôn dùng để khống chế con Hồn thú bất khuất, vốn không nghe lời, bị phong ấn trong Xạ Thần Xa: mỗi đạo phong ấn mở ra cần nắm một chữ chân ngôn. Việc Vương Lâm chỉ nắm phần chân ngôn khống chế gợi mở mối liên hệ giữa hắn với di sản, truyền thừa của vị tiên nhân luyện bảo.","nguon":["@c0500"]},{"id":"thuat-khong-che-quy-anh-to-den","name":"Thuật khống chế Quỷ ảnh","loai":"bi-thuat","loaiLabel":"Bí thuật khống quỷ","phamCap":"Công pháp môn phái","hePhai":"Môn phái Hắc y nam tử","soHuu":["Hắc y nhân (mặt sẹo)"],"blurb":"Dùng tơ mảnh màu đen từ ngực và tay để thu hồi và khống chế Thiên Quỷ.","detail":"Bí thuật của Hắc y nam tử dùng những sợi tơ mảnh màu đen tỏa ra từ ngực và tay để thu hồi, khống chế Thiên Quỷ (Quỷ ảnh). Khi thi triển, hắn phải đặt tay phải trên ngực để giữ thuật quỷ ảnh khỏi bị phá vỡ. Trong trận với Vương Lâm, thuật này không giữ nổi Thiên Quỷ vốn đã hạ quyết tâm bỏ trốn.","nguon":["@c0500"]},{"id":"ton-than-thuat","name":"Tổn Thần thuật","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Thiên Quỷ Đạo","soHuu":["La Vân"],"blurb":"Pháp môn hao tổn tinh hoa nguyên thần vĩnh viễn không khôi phục để bùng tốc độ bỏ trốn.","detail":"Khi nguyên thần lâm nguy, thuật này đốt tinh hoa nguyên thần (tổn thất vĩnh viễn, không thể khôi phục) để bùng nổ tốc độ tháo chạy. La Vân dùng để thoát khỏi quỷ phong của hồn thú nhưng vẫn bị Vương Lâm bắt kịp.","nguon":["@c0501"]},{"id":"bi-thuat-luyen-thien-quy","name":"Bí thuật luyện Thiên quỷ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Thiên Quỷ Đạo","soHuu":["Thiên Quỷ Đạo"],"blurb":"Bí thuật của Thiên Quỷ Đạo để bắt một Thiên Quỷ làm bản mạng quỷ linh.","detail":"Dùng máu phụ nữ có thai làm chất dẫn, nhiệt huyết thanh niên dẫn dắt, nguyên thần tu sĩ triệu tập; trải bảy bảy bốn mươi chín năm mới hấp dẫn được một Thiên Quỷ sinh ra từ hư vô, rồi dùng bí thuật bắt làm bản mạng quỷ linh phòng thân.","nguon":["@c0502"]},{"id":"thuat-bui-khi-hoa-han-quang","name":"Thuật đám bụi khí hóa hàn quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm dùng diệt Thiên quỷ: bụi khí thét gào lao như rồng rồi hóa vô số tia hàn quang bám lấy mục tiêu.","detail":"Vương Lâm vẽ tay vào hư không khiến đám bụi khí thét gào lao vào rãnh sâu như con rồng; bụi khí tiêu tan rồi hóa nhiều tia hàn quang khuếch tán bám lấy mục tiêu, hết đám này tới đám khác ngưng tụ đánh tới liên hồi, chẳng mấy chốc phủ đầy tro bụi lên thân đối phương.","nguon":["@c0502"]},{"id":"luyen-hon-tong-tam-mon","name":"Luyện Hồn Tông pháp thuật (tam môn)","cn":"","loai":"cong-phap","loaiLabel":"Hệ pháp môn","phamCap":"","hePhai":"Luyện Hồn Tông","soHuu":["Vương Lâm"],"blurb":"Hệ pháp môn của Luyện Hồn Tông gồm ba môn luyện hồn, trừu phách và tỏa thần.","detail":"Pháp thuật trục của Luyện Hồn Tông chia làm ba môn. Luyện hồn là luyện hóa linh hồn có sẵn để rút phách hoặc hút linh hồn người sống; trừu phách và luyện hồn là căn bản của tông; tỏa thần do các thế hệ chính thống tu luyện, vốn là phương pháp dùng để điều khiển Thập Ức Tôn Hồn Phiên. Luyện ra được hồn phiên là điều kiện chính thức để thành đệ tử của tông.","nguon":["@c0503"]},{"id":"thuat-hon-phien","name":"Thuật hồn phiên","cn":"","loai":"bi-thuat","loaiLabel":"Pháp thuật","phamCap":"","hePhai":"Luyện Hồn Tông","soHuu":["Vương Lâm"],"blurb":"Thuật Vương L��m định truyền cho cư dân thung lũng: dễ nhập môn, hợp việc chết chóc.","detail":"Thuật chế tác và dùng hồn phiên mà Vương Lâm dự định truyền cho cư dân sơn cốc nhằm gây dựng lực lượng riêng. Đặc tính dễ nhập môn, càng giết chóc càng tụ nhiều hồn phách làm tăng thực lực. Khẩu quyết bước đầu được lưu vào ngọc giản, nhưng Vương Lâm cố ý cài một sơ hở trí mạng chỉ mình biết để có thể trực tiếp khống chế hồn phiên của đệ tử thành vật của mình.","nguon":["@c0503"]},{"id":"phuong-phap-che-hon-phien-thay-the","name":"Phương pháp chế hồn phiên thay thế","cn":"","loai":"bi-thuat","loaiLabel":"Phép chế tác","phamCap":"","hePhai":"Luyện Hồn Tông nhất mạch","soHuu":["Vương Lâm","Thập Tam","Âu Dương Hoa"],"blurb":"Cách chế hồn phiên ứng biến do Vương Lâm sáng tạo khi thiếu tài liệu ở Thiên Vận Tinh.","detail":"Do tài liệu nơi yêu linh cực kỳ thiếu khuyết, Vương Lâm dùng cươn thụ chi mộc kết hợp da dã thú ngưng hóa bằng yêu lực và thủ ấn để miễn cưỡng bắt chước hiệu quả hồn phiên. Thứ thay thế này chỉ phong ấn được không quá mười hồn phách; thi triển đồng thời mười hồn phiên thì đạt một nửa uy lực của bách hồn phiên. Bên trong có một sơ hở trí mạng chỉ mình Vương Lâm biết.","nguon":["@c0505"]},{"id":"co-che-khong-che-hon-thu-vuong-lam","name":"Sơ hở khống chế hồn thú","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế cài sẵn","phamCap":"","hePhai":"Luyện Hồn Tông nhất mạch (đã cải biến)","soHuu":["Vương Lâm"],"blurb":"Backdoor Vương Lâm cài vào Luyện Hồn Thuật để khống chế mọi hồn thú do người học phong ấn.","detail":"Vương Lâm cố ý cải biến Luyện Hồn Thuật và phương pháp chế hồn phiên, gài một sơ hở cài sẵn lên cả công pháp lẫn hồn phiên. Hệ quả là mọi hồn thú do người học thuật (đã bị hắn cải biến) phong ấn đều bị Vương Lâm hoàn toàn điều khiển và chấn nhiếp, nắm quyền sinh sát toàn bộ lực lượng Luyện Hồn ở Thiên Vận Tinh. Khi sư tử cánh dài của Thập Tam phản phệ, chỉ một tiếng hừ của Vương Lâm đã khiến nó tan nát rồi thuần phục.","nguon":["@c0505"]},{"id":"tran-phap-vien-co-thien-thuy","name":"Trận pháp viễn cổ bộ lạc Thiên Thủy","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Viễn cổ","hePhai":"Bộ lạc Thiên Thủy","soHuu":["Bộ lạc Thiên Thủy"],"blurb":"Trận pháp viễn cổ phủ mười dặm, mạnh hơn trận thung lũng một bậc; ban đêm Yêu Linh hạ xuống vẫn an toàn.","detail":"Phản kích bằng sóng gợn màu xanh; hấp thu tổn thương chuyển thành phòng ngự tạo vòng tuần hoàn khó phá trong thời gian ngắn. Vương Lâm dùng Khai Thiên phủ chém vẫn không phá nổi nên phải đào vòng quanh ven trận rồi nhổ cả mảnh đất mười dặm.","nguon":["@c0507"]},{"id":"tran-phap-luyen-hon-hai-muoi-dam","name":"Trận pháp Luyện Hồn (hai mươi dặm)","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Cải biên","hePhai":"Bộ lạc Luyện Hồn","soHuu":["Vương Lâm","Bộ lạc Luyện Hồn"],"blurb":"Trận bảo vệ phạm vi hai mươi dặm do Vương Lâm dung hợp ba trận pháp để che chở bộ lạc Luyện Hồn.","detail":"Dung hợp trận cấm chế làm căn bản với trận thung lũng cũ và trận pháp mảnh đất mười dặm cướp từ bộ lạc Thiên Thủy, mở rộng phạm vi bảo vệ thành hai mươi dặm.","nguon":["@c0507"]},{"id":"thap-bang-chien-y","name":"Thập Băng Chiến Ý","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực hiếm thấy","hePhai":"Tả dực Yêu tương (Yêu linh chi địa)","soHuu":["Tả dực Yêu tương"],"blurb":"Thần thông của Tả dực Yêu tương: mười quyền đánh vào hư không, gồm mười lần biến hóa sụp đổ chồng chất.","detail":"Tả dực Yêu tương đánh mười quyền cực nhanh vào hư không, các quyền không có thực chất mà dung nhập vào hư vô, gồm mười lần biến hóa và sụp đổ chồng chất lên nhau; tới lần thứ mười đạt tới mức độ kinh người khó tin. Đây là thần thông cực hiếm thấy trong Tu Chân Giới. Yêu tương ném đòn này về phía Vương Lâm, hứa nếu tiếp được sẽ ban chức Đô thống. Vương Lâm nhìn ra manh mối, đứng vững như cây tùng, vận Sát lục tiên quyết kết hợp Hóa Ma chỉ để tiếp.","nguon":["@c0509"]},{"id":"sanh-an-phong-ho","name":"Sanh ấn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ấn pháp phòng hộ: hai ký hiệu màu xám hiện trên mi tâm rồi lan bao trùm toàn thân thành hai đạo phòng hộ.","detail":"Khi đối mặt lần sụp đổ thứ tư của Thập Băng Quyền Ý, Vương Lâm thu trường kiếm khí xám thành hai luồng khí chui vào cơ thể, trên mi tâm hiện hai ký hiệu màu xám lan ra bao trùm toàn thân, hóa thành hai đạo Sanh ấn phòng hộ để chống đỡ đợt công kích cực mạnh mà không phải lộ ra Hoàng Tuyền chỉ.","nguon":["@c0510"]},{"id":"huyet-thuat-gia-truyen-dieu-tich-tuyet","name":"Huyết thuật gia truyền","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Dòng Huyết tổ","soHuu":["Diêu Tích Tuyết"],"blurb":"Thuật gia truyền của dòng Huyết tổ, giúp người dùng cầm cự qua những đợt công kích cực mạnh.","detail":"Là thuật gia truyền của Diêu Tích Tuyết, con gái Huyết tổ. Ba năm trước nhờ vận dụng thuật này mà nàng sống sót quá lần sụp đổ thứ năm của Thập Băng Quyền Ý — một thần công mà nếu không có thuật hộ thân thì khó qua nổi lần thứ tư.","nguon":["@c0510"]},{"id":"than-thong-niem-tin","name":"Thần thông Niềm tin","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cảnh giới thần thông tinh thần","hePhai":"","soHuu":["Vương Lâm","Tả Dực tướng quân"],"blurb":"Cảnh giới thần thông dựa trên niềm tin tinh thần thay vì tu vi, một niềm tin vững chắc đủ để ảnh hưởng và thay đổi trời đất.","detail":"Thần thông Niềm tin là bản chất ẩn dưới Thập Băng Quyền Ý: đạo tâm thăng hoa tới đỉnh, nguyên thần dung nhập đạo tâm, chỉ còn lại một niềm tin vững chắc có thể đổi cả thiên địa. Niềm tin của Tả dực Yêu tướng là ‘tất thắng’, tích lũy từ kinh nghiệm sa trường và tâm niệm của vô số kẻ từng bại dưới quyền ý. Vương Lâm ngộ ra rằng phá thần thông này không dựa vào tu vi mà phải dung niềm tin của bản thân vào pháp thuật, biến cuộc đối kháng lực lượng thành đối kháng niềm tin; hắn giao ‘linh hồn’ cho Hóa Ma chỉ và chỉ một lời đã phá được đợt sụp đổ thứ bảy.","nguon":["@c0511"]},{"id":"ma-niem","name":"Ma niệm","loai":"khac","loaiLabel":"Ý niệm","phamCap":"Ý niệm","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý niệm Vương Lâm lĩnh ngộ: không phải giết chóc hay tất thắng mà là nghịch thiên, tùy ý làm, phá hư đạo pháp, tự đi con đường riêng.","detail":"Khi dồn niềm tin vào Hóa Ma chỉ, Vương Lâm nhận ra ý niệm chống đỡ Thập Băng Quyền Ý không phải là giết chóc cũng không phải tất thắng, mà là Ma niệm — nghịch thiên, tùy ý đoạt sinh mạng trí tuệ, phá hư đạo pháp đã định, tự mở lấy con đường riêng nên gọi là Ma. Chính ý niệm này khiến tiên lực trong người hắn vô thanh hóa thành ma khí và Hóa Ma chỉ phát huy uy lực chân chính.","nguon":["@c0511"]},{"id":"thap-bang-quyen","name":"Thập Băng Quyền","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Khảo nghiệm","hePhai":"Vân Lệ Hải (Tả Dực Yêu tương)","soHuu":["Vân Lệ Hải (Tả Dực Yêu tương)"],"blurb":"Mười quyền khảo nghiệm của Vân Lệ Hải, mỗi quyền là một ‘lần sụp đổ’ từ hư vô hóa thành.","detail":"Quyền pháp Vân Lệ Hải dùng làm khảo nghiệm thực lực: gồm mười quyền, mỗi quyền gọi là một ‘lần sụp đổ’, từ hư vô hóa thành mà công kích. Càng về sau uy lực càng tăng — lần thứ tám hóa thành dạng nước lũ cuồn cuộn với uy lực chưa từng có, lần thứ chín im lìm xuất hiện áp tới khi lần trước chưa kịp tan. Người chủ thi triển chỉ cần chộp tay là thu lại được toàn bộ quyền ý, trời đất lập tức khôi phục như cũ. Vương Lâm nhập ma vượt được tám lần rồi chủ động lùi trước quyền thứ chín.","nguon":["@c0512"]},{"id":"tru-tien-tran","name":"Tru Tiên trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Quân yêu Cổ Yêu thành","soHuu":["Thống lĩnh (Nghiêu Lĩnh, Cổ Yêu thành)"],"blurb":"Trận pháp sát phạt mà thống lĩnh Nghiêu Lĩnh định thi triển để giết người ngoài đến.","detail":"Trận pháp được thống lĩnh cũ tính dùng để giết người ngoài đến nếu đối phương mạnh; bị yêu binh cảnh báo rằng động trận này trong nội bộ sẽ bị Yêu Tương đại nhân trách phạt.","nguon":["@c0513"]},{"id":"luyen-the-thuat-thap-tam","name":"Luyện Thể thuật (Thập Tam)","cn":"","loai":"luyen-the","loaiLabel":"Công pháp luyện thể","phamCap":"","hePhai":"","soHuu":["Thập Tam"],"blurb":"Công pháp luyện thể của Thập Tam, vốn chưa đầy đủ nên uy lực sau tu luyện chưa mạnh.","detail":"Dù công pháp còn khuyết thiếu, Thập Tam vẫn tung được một quyền đánh trọng thương yêu binh, hất đối phương phun máu văng đi mấy trượng.","nguon":["@c0513"]},{"id":"yeu-luc-pha-than","name":"Yêu lực phá thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông yêu thuật","phamCap":"","hePhai":"Quân yêu Cổ Yêu thành","soHuu":[],"blurb":"Chiêu của sáu yêu binh, phát ra sáu luồng yêu lực mạnh như rồng nổi giận để bức lui hồn phách.","detail":"Sáu yêu binh đồng loạt ra tay, phóng sáu luồng yêu lực cuồng bạo đẩy lui đám hồn phách của Hồn phiên; khi mất khống chế, sáu đạo yêu lực này bay thẳng vào mi tâm Vương Lâm và bị ma niệm của hắn hút trọn.","nguon":["@c0513"]},{"id":"phap-thuat-dung-lau-bun-dat","name":"Pháp thuật dựng lầu bùn đất","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp thuật điều khiển đất đá, lập tức dựng lên kiến trúc từ bùn đất.","detail":"Vương Lâm nhấn tay xuống đất, mặt đất rung chuyển và phun lên, tạo tức thì một ngôi lầu hai tầng bằng bùn đất uy nghiêm giữa quân doanh. Uy thế của pháp thuật chấn nhiếp cả Tư Mã Viêm lẫn chín ngàn yêu binh.","nguon":["@c0517"]},{"id":"thuat-tai-tao-mau-lam-dieu-tich-tuyet","name":"Thuật tái tạo bằng máu lam","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Diêu Tích Tuyết"],"blurb":"Bí thuật phân thân và hồi sinh thân thể bằng một giọt máu lam kết hợp Huyết Hồn đan.","detail":"Diêu Tích Tuyết bóp nát cây đèn trắng lấy ra giọt máu lam, cắn ngón tay vẽ phù văn bằng máu, dung hợp giọt máu lam rồi điểm vào mi tâm trước khi xuất ra trở lại để xông vào “nơi đó”. Khi thất bại, giọt máu lam sôi trào phình thành quả cầu máu lam, các phù văn gắn lên tái tạo lại thân thể nàng — cơ chế hồi sinh dựa vào Huyết Hồn đan.","nguon":["@c0517"]},{"id":"that-bang-quyen-yeu-tuong","name":"Thất Băng quyền","loai":"cong-phap","loaiLabel":"Quyền pháp","phamCap":"","hePhai":"Yêu Tương","soHuu":["Yêu Tương đại nhân"],"blurb":"Quyền pháp của Yêu Tương; Diêu Tích Tuyết lấy việc có thể tiếp được Thất Băng quyền làm thước đo cho rằng tu vi Vương Lâm vừa đủ để nhờ cậy.","detail":"Công pháp quyền kình của Yêu Tương. Trong tính toán nhân lực ở Cổ Yêu thành, Diêu Tích Tuyết dùng tiêu chí “có thể tiếp được Thất Băng quyền của Yêu Tương” để xét xem ai đủ tu vi giúp nàng, và kết luận chỉ Vương Lâm đáp ứng được.","nguon":["@c0518"]},{"id":"tran-cam-che-muoi-tam-phong-an","name":"Trận pháp cấm chế mười tám phong ấn","loai":"khac","loaiLabel":"Trận pháp / cấm chế","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trận pháp cấm chế bí ẩn chưa rõ tên; khi mở ra sẽ xoay tròn, bên trong có mười tám phong ấn, phá thành công thì sống, thất bại thì chết.","detail":"Trận pháp cấm chế giấu kín trong Yêu Linh chi địa, muốn tới được phải có một loại pháp bảo đặc biệt mà hiện chỉ Diêu Tích Tuyết có thể vào. Trận mở ra sẽ xoay tròn, bên trong xếp mười tám tầng phong ấn; phá giải mang tính sinh tử — thành công thì sống, thất bại thì chết. Diêu Tích Tuyết một mình chỉ phá được tới phong ấn thứ mười một, đã thất bại bốn lần và mỗi lần phải dùng Huyết Hồn đan hồi sinh, nên tìm Vương Lâm trợ lực.","nguon":["@c0518"]},{"id":"tran-an-than-bay-pho-tuong","name":"Trận ẩn thân bảy pho tượng","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Thượng cổ","hePhai":"Huyết Tổ sáng tạo","soHuu":["Diêu Tích Tuyết","Huyết Tổ Diêu Tinh Hải"],"blurb":"Trận pháp do Huyết Tổ sáng tạo, dùng bảy pho tượng đỏ chui xuống đất tạo nguồn lực vô hình khiến thần thức không soi thấy chính mình.","detail":"Người thi triển kết ấn, cắn lưỡi vẽ ký tự máu to trăm trượng in lên mặt đất; bảy pho tượng đỏ bay tới bảy điểm rồi chui xuống đất tạo nguồn lực vô hình. Trong phạm vi trăm trượng, thần thức kẻ ở trong không thể cảm nhận được thân ảnh của chính mình, như soi gương mà không thấy mình. Diêu Tích Tuyết nói trận này tinh diệu tới mức cả Yêu Tương cũng không phát hiện ra.","nguon":["@c0520"]},{"id":"truyen-tong-tran-yeu-linh-chi-dia","name":"Truyền tống trận (Yêu Linh chi địa)","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Thượng cổ","hePhai":"Huyết Tổ bố trí","soHuu":["Diêu Tích Tuyết","Huyết Tổ Diêu Tinh Hải"],"blurb":"Điểm truyền tống do Huyết Tổ bố trí sẵn, chỉ mở được trong Yêu Linh chi địa lúc trăng tím mạnh nhất nửa năm một lần.","detail":"Trận kích hoạt khi yêu khí trong vùng lên cực điểm và la bàn đỏ lóe sáng một nhịp hô hấp; ánh trăng tím bùng phủ tím mặt đất, một luồng đỏ như kiếm xuyên hiện ra để người vào lao tới. Trận chỉ truyền tống được trong phạm vi Yêu Linh chi địa, đưa người tới không gian Tôn Thú nơi đặt bình đài trận pháp cùng nguồn gốc.","nguon":["@c0520"]},{"id":"luyen-tien-tinh","name":"Luyện Tiên tinh","loai":"cong-phap","loaiLabel":"Kỹ thuật tu luyện","phamCap":"Tự sáng","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Vương Lâm vận dụng kết cấu yêu tinh học ở bộ lạc Luyện Hồn để cô đọng tiên lực thành ‘Tiên tinh’.","detail":"Sau thời gian dài nghiên cứu yêu tinh ở bộ lạc Luyện Hồn, Vương Lâm nắm rõ kết cấu yêu tinh và mượn nó để nén tiên lực hấp thu từ tiên ngọc thành một tinh thể giống yêu tinh nhưng tỏa ra tiên lực. Mỗi viên Tiên tinh chứa lượng tiên lực bằng khoảng một phần mười số tiên ngọc đã dùng, tiện cất giữ và vận dụng.","nguon":["@c0520"]},{"id":"tao-an-ky-buoc-duong-ton-thu","name":"Tạo ấn ký bước trên đường Tôn Thú","loai":"bi-thuat","loaiLabel":"Pháp môn","phamCap":"Bí truyền","hePhai":"Huyết Tổ truyền thừa","soHuu":["Diêu Tích Tuyết"],"blurb":"Ngưng thần cảm ngộ ý cảnh bản thân để tạo ra ấn ký, nhờ đó có thể bước trên con đường thân thể giao long Tôn Long.","detail":"Tại không gian Tôn Thú, người tu phải ngồi ngưng thần, cảm ngộ ý cảnh của chính mình rồi tạo thành ấn ký riêng. Có được ấn ký này mới đủ tư cách bước lên con đường nhỏ uốn lượn — thực chất là cơ thể con giao long Tôn Long do người dùng thần thông bố trí.","nguon":["@c0520"]},{"id":"suy-dien-cam-che-vuong-lam","name":"Suy diễn cấm chế","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Cấm chế chi đạo","soHuu":["Vương Lâm"],"blurb":"Thuật vận cấm chế trong hai mắt để suy diễn, nhìn thấu bản chất sự vật.","detail":"Vương Lâm vận cấm chế ngưng trong hai con mắt rồi suy diễn với tốc độ ngày càng nhanh. Nhờ vậy hắn nhìn thấu pho tượng đá ba mắt ở bình đài thứ ba vốn không phải là tượng, mà chỉ là một đống cấm chế chồng lớp lên nhau — từ đó tìm ra cách phân giải và hấp thu chúng.","nguon":["@c0522"]},{"id":"kim-phu-ba-net-phu-van","name":"Kim phù (ba nét phù văn)","cn":"","loai":"bi-thuat","loaiLabel":"Phù văn bí thuật","phamCap":"Ẩn chứa ấn ký thiên đạo","hePhai":"Động phủ tiên nhân đường Tôn Long","soHuu":["Vương Lâm"],"blurb":"Phù văn vẽ ba nét trong mắt hoặc hư không, khi dung tiên lực thì phát kim quang cực mạnh xua tan hắc khí trên đài phong ấn.","detail":"Vương Lâm cảm ngộ và vẽ thành công ba nét, ký hiệu phát kim quang uy thế ngang hàng cường giả lớp phụ thân Diêu Tích Tuyết, đủ buộc nàng dùng huyết ngọc trăm năm hóa giải. Hắn không vẽ ra nổi nét thứ tư vì thiếu căn cứ; nếu phù chưa hoàn thành thì ký hiệu tự sụp đổ. Cảm ngộ được kim phù mới đạt tư cách bước vào động thí luyện; nghi vấn rằng mười tám ký hiệu hợp lại có thể là một môn tiên thuật bất thành.","nguon":["@c0523"]},{"id":"phuc-hoat-than-thong","name":"Phục Hoạt Thần Thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Truyền thừa Huyết Quân","soHuu":["Diêu Tích Tuyết"],"blurb":"Thần thông mà Động Phủ Chi Linh yêu cầu Diêu Tích Tuyết thi triển để chứng minh thân phận truyền nhân.","detail":"Khi nhận ra Diêu Tích Tuyết mang công pháp Huyết Quân năm xưa, Động Phủ Chi Linh đòi nàng thi triển Phục Hoạt Thần Thông rồi cút khỏi cửa động phủ.","nguon":["@c0523"]},{"id":"than-thong-phong-an-mi-tam","name":"Thần thông phong ấn (dấu ấn mi tâm)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Điểm một dấu khí xám lên mi tâm đối thủ, làm đứt kinh mạch và phong ấn toàn thân giữa sự sống và cái chết.","detail":"Vương Lâm dùng để giam Diêu Tích Tuyết trong trạng thái không thể chết, qua đó vô hiệu hóa Huyết Hồn Đan vốn phải chết mới phát huy tác dụng, khiến nàng cô độc bị giam giữ lâu dài.","nguon":["@c0523"]},{"id":"tran-phap-tron-do-dieu-tich-tuyet","name":"Trận pháp tròn màu đỏ","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp huyết hệ","phamCap":"","hePhai":"Huyết công","soHuu":["Diêu Tích Tuyết"],"blurb":"Diêu Tích Tuyết phun máu hóa ký hiệu đỏ rồi dựng trận tròn trên hai tay để chắn đạo kiếm khí thứ ba.","detail":"Trận pháp vỡ vụn trước kim quang, kiếm khí tan thành điểm sáng dung nhập cơ thể buộc nàng ngồi xuống vận tiên lực đối kháng.","nguon":["@c0523"]},{"id":"mai-hoa-thap-bat-cam","name":"Mai Hoa Thập Bát Cấm","loai":"bi-thuat","loaiLabel":"Bí thuật phá cấm","phamCap":"Thượng cổ","hePhai":"Dòng chính thống thượng cổ Tu Chân Giới","soHuu":[],"blurb":"Thủ pháp phá cấm chế cực tinh xảo thời thượng cổ, khi phá phong ấn để lại dấu vết hình hoa mai.","detail":"Một môn cấm thuật phá-cấm tinh xảo bậc nhất thời thượng cổ Tu Chân Giới, dấu vết phá giải để lại tựa như hoa mai nở. Pháp môn rất coi trọng dòng chính thống, người ngoài tuyệt không được truyền; đệ tử chính thống tối đa chỉ học đến Cửu Cấm, duy chỉ chưởng môn mới học hết Thập Bát Cấm. Người nắm trọn thuật này có thể đạt độ nắm chắc phá giải bảy phần trở lên. Trong động phủ tiên cấm, tiền nhân đầu tiên tiến vào chính là người dùng môn này, cao ngạo chỉ lấy vật quý.","nguon":["@c0524"]},{"id":"ho-phu-than-thong","name":"Hộ Phủ Thần Thông","loai":"than-thong","loaiLabel":"Thần thông phòng thủ","phamCap":"Tiên gia","hePhai":"Chủ nhân động phủ tiên cấm","soHuu":[],"blurb":"Thần thông phòng thủ động phủ, biểu hiện bằng ký hiệu vàng trên mười một đài bên ngoài.","detail":"Thần thông canh giữ động phủ, thể hiện qua các ký hiệu màu vàng trên mười một đài bên ngoài cửa đá. Khi thần thông còn hiệu lực thì không ai tiến vào được; chủ nhân đã phong ấn lại nhưng cố ý không để lại đầu mối điều khiển sau khi rời đi.","nguon":["@c0524"]},{"id":"tien-cam","name":"Tiên Cấm","loai":"bi-thuat","loaiLabel":"Cấm chế tiên giới","phamCap":"Tiên gia","hePhai":"Tiên giới","soHuu":[],"blurb":"Thủ pháp phong ấn của tiên giới, hiếm thấy cả ở thời thượng cổ; đặc điểm có đường sinh không cố định.","detail":"Cấm chế bậc tiên giới, theo sách cổ thì hiếm thấy ngay cả ở thời thượng cổ. Đặc trưng là có đường sinh biến đổi không cố định, dịch chuyển theo cấm chế. Trong động phủ của chủ nhân giấu mặt, tiên cấm bao phủ toàn bộ kiến trúc cả trong lẫn ngoài, khiến tiên ngọc nền móng không thể đào lấy.","nguon":["@c0524"]},{"id":"cam-che-phong-an-khu-vuon","name":"Cấm chế phong ấn khu vườn","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"Tiên gia","hePhai":"Động phủ tiên cấm","soHuu":[],"blurb":"Trận pháp trung tâm của mọi cấm chế quanh động phủ, biến hóa hơn vạn loại, phát động kéo theo toàn bộ.","detail":"Cấm chế bao quanh khu vườn còn nguyên vẹn trong động phủ, là trung tâm của tất cả cấm chế xung quanh với hơn một vạn biến hóa. Một khi phát động sẽ kéo theo toàn bộ hệ thống, tạo cơn lốc đen cùng sấm sét tia chớp tựa Du Long, tu sĩ Vấn Đỉnh đứng trong đó ba hơi thở cũng chết. Đường sinh tiến vào không cố định, biến đổi theo cấm chế và có thể đột ngột xoay ngược đổi phương hướng vận chuyển.","nguon":["@c0524"]},{"id":"tran-phap-truyen-tong-huyet-to","name":"Trận pháp truyền tống Huyết Tổ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thông thiên (do Huyết Tổ lưu)","hePhai":"Di sản Huyết Tổ","soHuu":["Vương Lâm"],"blurb":"Trận truyền tống Huyết Tổ lưu trên cái đài đầu tiên trong động phủ, khớp với la bàn huyết sắc để dịch chuyển.","detail":"Trận pháp do Huyết Tổ để lại trên cái đài đầu tiên của động phủ, phải khớp với la bàn huyết sắc mới đổi được phương vị dịch chuyển. Vương Lâm hiệu chỉnh trong ba ngày rồi dùng ba mươi ngày bố trí vô số cấm chế cải tạo nó thành cạm bẫy: người ngoài nào bước vào sẽ bị truyền đi rồi truyền về liên tục cho tới khi vách không gian vỡ, bị cuốn vào khe không gian.","nguon":["@c0526"]},{"id":"tran-phap-trong-la-ban-huyet-sac","name":"Trận pháp trong la bàn huyết sắc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Di sản Huyết Tổ","soHuu":["Vương Lâm"],"blurb":"Trận nhỏ bên trong la bàn huyết sắc, kim đong đưa luôn biến hóa, phải khớp với truyền tống trận mới đổi phương được.","detail":"Bên trong la bàn huyết sắc có một trận pháp nhỏ đong đưa theo kim, biến hóa không ngừng; chỉ khi khớp với trận truyền tống ở cái đài mới đổi được phương vị dịch chuyển. Trong trận này vốn lưu thần thức Diêu Tích Tuyết (không có Huyết Tổ) nên Vương Lâm xóa được và lưu thần thức của mình vào.","nguon":["@c0526"]},{"id":"huyen-vu-hoa-than-do-thong","name":"Huyền Vũ hóa thân (Đô Thống)","cn":"","loai":"than-thong","loaiLabel":"Yêu lực hóa thân","phamCap":"Anh Biến hậu kỳ","hePhai":"Yêu tộc","soHuu":["Đô Thống Hắc Giáp quân"],"blurb":"Hóa thân Huyền Vũ kích thước trăm trượng của Đô Thống Hắc Giáp quân, lưng và đuôi đầy gai nhọn như giáo đen.","detail":"Khi mất khí thế trước Vương Lâm, Đô Thống hóa thân Huyền Vũ trăm trượng, lưng và đuôi mọc đầy gai nhọn như giáo đen, một cú vung có thể phá nát không gian, dùng để chống đỡ Tịch Diệt Chỉ.","nguon":["@c0526"]},{"id":"cam-bay-than-thuc-huyet-to","name":"Cạm bẫy thần thức (Huyết Tổ)","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Thông thiên","hePhai":"Di sản Huyết Tổ","soHuu":["Huyết Tổ Diêu Tinh Hải"],"blurb":"Lạc ấn thần thức phong trên túi trữ vật phóng huyết quang chống cự; túi thứ tư ẩn một đạo tử tuyến giết kẻ không quan sát kỹ.","detail":"Thần thức phong ấn trên các túi trữ vật của Diêu Tích Tuyết phóng huyết quang chống cự khi bị phá. Riêng túi thứ tư có một đạo tử tuyến ẩn trên huyết quang, nghi là cạm bẫy thần thức của chính Huyết Tổ — ai không quan sát kỹ mà cưỡng phá sẽ bị giết, khiến Vương Lâm thu thần thức, không dám mở.","nguon":["@c0526"]},{"id":"yeu-hai-bach-lang","name":"Yêu Hải Bách Lãng","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tuyệt chiêu Anh Biến","hePhai":"Yêu tộc","soHuu":["Mạc Lệ Hải (Yêu Tướng)"],"blurb":"Tuyệt chiêu của yêu tướng Mạc Lệ Hải, biến yêu lực hư vô thành biển cả thực thể tung ra sóng yêu khí trùng trùng.","detail":"Mạc Lệ Hải vỗ tay biến yêu lực hư vô thành thực thể biển cả rộng mười dặm, từ đó tung ra hàng chục đợt sóng yêu khí công kích (ba mươi đến sáu mươi đợt nối nhau), ẩn chứa thần thông vượt trên quyền ý. Cấm chế thông thường và cả Huyết sắc Ngọc phù đều bị sóng phá vỡ, Vương Lâm phải liên tục lùi để tìm cách phá giải.","nguon":["@c0529"]},{"id":"chuong-an-hu-ao-vo-danh","name":"Chiêu vô danh (chưởng ấn hư ảo)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cảm ngộ tiên giới (chưa hoàn chỉnh)","hePhai":"Thủ ấn tiên giới","soHuu":["Vương Lâm"],"blurb":"Chưởng ấn khổng lồ mang khí thế hủy thiên diệt địa nhưng thực chất chỉ là hư ảnh vô lực, dùng để đánh tâm lý.","detail":"Vương Lâm nhắm mắt vận dụng cảm ngộ về thủ ấn khổng lồ từng thấy ở tiên giới (đã dùng trong trận với Hồng Điệp), tạo một chưởng ấn khổng lồ mang khí thế hủy diệt thiên địa khiến đối thủ cảm thấy không thể kháng cự. Thực chất chưởng ấn chỉ là hư ảnh không có lực công kích, xuyên qua thân Mạc Lệ Hải mà không gây biến hóa; Vương Lâm gọi đây là chiêu vô danh, dùng tâm lý chiến buộc đối phương không dám đánh cuộc mạng sống. Mạc Lệ Hải nhận xét chiêu này Vương Lâm chưa học toàn bộ.","nguon":["@c0529"]},{"id":"phu-van-than-thong-khi-xam","name":"Phù văn thần thông (ba nét khí xám)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông phù văn","hePhai":"Phù văn tượng đá","soHuu":["Vương Lâm"],"blurb":"Vương Lâm dùng khí xám vẽ ba nét phù văn, dung hợp lực màu vàng từ tượng đá thứ hai để bắn khí xám xuyên Yêu Hải.","detail":"Khi phù văn màu vàng hấp thu từ tượng đá thứ hai hiện rõ trong đầu và quấy nhiễu tiên lực, Vương Lâm thuận theo dùng khí xám vẽ ba nét bút thành phù văn thần thông. Lực màu vàng hòa tan dung nhập, bắn ra ba luồng khí xám xuyên qua Yêu Hải đánh thẳng Mạc Lệ Hải, buộc hắn phải dựng màn chắn yêu lực chống đỡ và kinh ngạc khen thần thông của phù văn.","nguon":["@c0529"]},{"id":"cu-linh-cuu-tu","name":"Cự Linh Cửu Tu","loai":"luyen-the","loaiLabel":"Công pháp luyện thể","phamCap":"Thần thông luyện thể chín tầng","hePhai":"","soHuu":["Vương Lâm","Thập Tam"],"blurb":"Công pháp thần thông tu luyện cơ thể gồm chín tầng, ghi trong ngọc giản; Vương Lâm chỉ truyền lại sáu tầng đầu.","detail":"Cự Linh Cửu Tu là một bộ công pháp thần thông luyện thể chia làm chín tầng, được ghi chép trong ngọc giản mà Vương Lâm thu được trước đó. Vương Lâm ghi nhớ trọn chín tầng khẩu quyết rồi xóa đi ba tầng phía sau, chỉ chép lại sáu tầng đầu vào một ngọc giản màu xanh và truyền cho Thập Tam.","nguon":["@c0530"]},{"id":"diet-the-ap-nguyen-cong","name":"Diệt Thế Áp Nguyên Công","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Công pháp yêu lực","hePhai":"Truyền thừa lão già hắc y","soHuu":["Hổ Bào"],"blurb":"Công pháp lão già hắc y truyền cho Hổ Bào; chỉ cần tu đến tầng thứ tư sẽ có yêu lực vô tận.","detail":"Diệt Thế Áp Nguyên Công là công pháp do lão già hắc bào truyền cho Hổ Bào sau khi cứu hắn khỏi hắc lao. Lão nói chỉ cần tu luyện đến tầng thứ tư sẽ có yêu lực vô tận, là một phần trong kế hoạch bồi dưỡng Hổ Bào thành Yêu Vệ.","nguon":["@c0530"]},{"id":"khau-quyet-chu-nhan-luyen-yeu-ve","name":"Khẩu quyết của chủ nhân (luyện Yêu Vệ)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bí thuật truyền từ chủ nhân hắc tháp","hePhai":"Chủ nhân (bộ giáp hắc tháp)","soHuu":["Lão già hắc bào (ân công của Hổ Bào)"],"blurb":"Khẩu quyết do chủ nhân trong hắc tháp truyền xuống, ngưng tụ toàn bộ tuổi thọ và tiềm lực trong một canh giờ rồi bùng nổ biến tu sĩ thành Yêu Vệ.","detail":"Là khẩu quyết bí truyền mà chủ nhân trong bộ giáp hắc tháp truyền cho lão già hắc y. Người tu luyện ngưng tụ toàn bộ tuổi thọ và tiềm lực của mình trong một canh giờ rồi bùng nổ để biến thành một Yêu Vệ. Lão già định cho Hổ Bào tu luyện sau khi hắn hấp thụ lượng lớn hồn phách qua Luyện Hồn Thuật.","nguon":["@c0530"]},{"id":"hon-phach-thu-than","name":"Hồn Phách Thủ Thần","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm","Âu Dương Hoa","Bộ lạc Luyện Hồn"],"blurb":"Pháp môn phòng thủ thần hồn dùng để chống lại thuật Linh Thang Loạn Thần khi tiềm nhập bộ lạc khác.","detail":"Vương Lâm chỉ định cho bộ lạc Luyện Hồn dùng Hồn Phách Thủ Thần làm lá chắn thần hồn khi mấy trăm tộc nhân tiềm nhập các bộ lạc lớn nhỏ; cốt yếu là vô hiệu hóa pháp thuật phòng vệ Linh Thang Loạn Thần thường được các bộ lạc bố trí để phát hiện và làm loạn thần kẻ xâm nhập.","nguon":["@c0531"]},{"id":"linh-thang-loan-than","name":"Linh Thang Loạn Thần","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Các bộ lạc lớn nhỏ vùng Yêu Linh"],"blurb":"Pháp thuật phòng vệ bộ lạc gây loạn thần kẻ xâm nhập, được Hồn Phách Thủ Thần khắc chế.","detail":"Mỗi bộ lạc lớn nhỏ trong vùng Vương Lâm nhắm tiềm nhập đều có Linh Thang Loạn Thần như một lớp cấm chế phát hiện và làm loạn thần kẻ ngoại lai; muốn xâm nhập thành công phải dùng Hồn Phách Thủ Thần chống đỡ.","nguon":["@c0531"]},{"id":"thap-bat-yeu-ma-than","name":"Thập Bát Yêu Ma Thân","cn":"","loai":"luyen-the","loaiLabel":"Luyện Thể","phamCap":"","hePhai":"","soHuu":["Mạc Lực Hải"],"blurb":"Công pháp luyện thể hợp luyện đủ mười tám bộ ma thân, là vốn liếng then chốt của Yêu tướng Mạc Lực Hải.","detail":"Mạc Lực Hải tu Thập Bát Yêu Ma Thân, hiện đã luyện hóa được mười bảy bộ; bộ thứ mười tám — gọi là Thập Tam — bị Vương Lâm mang đi khỏi Cổ Yêu thành khiến hắn dở dang. Nếu được trợ lực hoàn tất công pháp, hắn tự tin vào nổi vòng ba cuộc chiến Yêu tướng, lấy tư cách vào Cổ Yêu điện tu luyện rồi thành phó soái.","nguon":["@c0531"]},{"id":"tho-nap-long-khi","name":"Thổ nạp long khí","loai":"cong-phap","loaiLabel":"Công pháp tu luyện","phamCap":"","hePhai":"Thiên Yêu quận","soHuu":[],"blurb":"Hấp thu lớp sương mỏng do chín dãy núi quanh Thiên Yêu thành tỏa ra để tăng tu vi.","detail":"Sáng sớm Thiên Yêu thành phủ một lớp sương mỏng tụ từ chín dãy núi bao quanh, được Yêu Đế gọi là long khí. Yêu tộc trong thành thổ nạp loại sương khí này có thể bồi bổ và tăng tiến tu vi, nên long khí trở thành phúc lợi đặc thù của kinh đô.","nguon":["@c0532"]},{"id":"than-thong-tam-thuc-mac-le-hai","name":"Thần Thông Tam Thức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thiên Yêu quận","soHuu":["Mạc Lệ Hải"],"blurb":"Bộ thần thông ba thức của Mạc Lệ Hải: Thập Băng Quyền Ý (thức một), Yêu Hải Bách Lãng (thức hai) và thức cuối do đích thân Yêu Đế thân truyền với uy lực khổng lồ.","detail":"Thần thông trục của Mạc Lệ Hải gồm ba thức nối tiếp tăng tiến. Thức một là Thập Băng Quyền Ý — quyền như gió gào, hư vô tan vỡ. Thức hai là Yêu Hải Bách Lãng. Thức ba do chính Yêu Đế thân truyền, uy lực được mô tả là khổng lồ và chưa từng thi triển; Thạch Tiễn cảnh báo đây là chìa khóa khiến Mạc Lệ Hải đáng gờm trong cuộc chiến Yêu tướng.","nguon":["@c0533"]},{"id":"luc-chi-kiem-quyet","name":"Lục Chỉ Kiếm Quyết","cn":"","aliases":["Lục Chỉ Yêu Kiếm"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Tiễn"],"blurb":"Thần thông sở trường của Thạch Tiễn, bị Mạc Lệ Hải gọi mỉa là Lục Chỉ Yêu Kiếm; uy lực khó lường.","detail":"Khi thi triển, người dùng cong tay phải điểm năm chỉ cực nhanh theo thứ tự (ngón trỏ rồi ngón giữa…), sau đó khép năm ngón thành chùy điểm tới, tạo tiếng nổ và sóng xung khuếch tán. Trong lần đấu thử với Thập Băng Quyền Ý của Mạc Lệ Hải, dù cả hai nén lực ở mức thấp nhất, chiêu vẫn làm nứt cả bốn chân chiến mã. Mạc Lệ Hải đánh giá uy lực khó lường.","nguon":["@c0533"]},{"id":"sat-luc-chi-khi","name":"Sát Lục Chi Khí","cn":"","loai":"than-thong","loaiLabel":"Sản vật thần thông","phamCap":"","hePhai":"Sát Lục Tiên Quyết","soHuu":["Vương Lâm"],"blurb":"Hôi khí xoay chuyển giữa kẽ ngón tay, sản vật luyện hóa từ Sát Lục Tiên Quyết.","detail":"Khí hôi luyện hóa được khi giết chóc hoặc thu từ Yêu binh không rõ con nào; cơ chế sinh ra chưa được giải thích, mỗi đạo như do ngẫu nhiên đoạt được — có khi nén giận xuất thủ thì luyện được một đạo, có khi lòng không dao động vẫn có. Vương Lâm tu vài năm mới luyện ra, hiện khống chế năm đạo, tính cả một đạo trên người là sáu; bên trong còn ẩn chứa huyền bí chưa lĩnh ngộ.","nguon":["@c0534"]},{"id":"sat-luc-khi-nam-thuong-long","name":"Sát lục khí (Năm con thương long)","cn":"","loai":"than-thong","loaiLabel":"Thần thông sát khí","phamCap":"","hePhai":"Sát Lục Tiên quyết","soHuu":["Vương Lâm"],"blurb":"Năm đạo khí màu xám của Vương Lâm hình thành năm con thương long; bị đánh tan thì tự dung hợp lại, len qua phòng ngự công kích, sắc bén hơn yêu kiếm.","detail":"Vương Lâm vung tay tạo ra năm đạo sát lục khí màu xám hóa thành năm con thương long lao tới. Khi bị đánh tan, chúng không tan biến mà tự dung hợp lại thành một thể, len qua quyền phong đánh thẳng tới mục tiêu. Thứ khí xám này sắc bén so với yêu kiếm, lại ẩn chứa một biến hóa khó giải có thể dẫn động sinh cơ trong cơ thể đối phương. Mạc Lệ Hải nhận xét chỉ năm đạo đã chấn động được yêu giáp của hắn; nếu hình thành tới mấy ngàn đạo thì uy lực cực kỳ đáng sợ.","nguon":["@c0535"]},{"id":"sat-luc-yeu-dao","name":"Sát lục yêu đạo","aliases":["Tâm hóa yêu"],"loai":"than-thong","loaiLabel":"Yêu đạo tu luyện","phamCap":"Không rõ","hePhai":"Hồng lao","soHuu":["Nam tử họ Hứa"],"blurb":"Con đường tu luyện sát đạo dùng tâm hóa yêu, biểu hiện sát tâm như kiếm chưa rời vỏ.","detail":"Đạo tu của nam tử họ Hứa ở Hồng lao, dùng tâm hóa yêu để luyện sát lục. Khi hắn biểu lộ sát tâm, không hề tỏa ra sát khí mà người đối diện vẫn lông tóc dựng ngược, nguyên thần rúng động — ví như kiếm chưa rời vỏ đã khiến người khác chấn động. Hứa tự xưng là người duy nhất trong mười người ở Hồng lao đi con đường này.","nguon":["@c0536"]}]};
